import type { Drill } from "./types";

// Education / early drills, keyed by module slug — 25 per module.
// New teacher / teaching assistant / corporate trainer in their first years:
// parent emails, classroom announcements, principal updates, report-card
// comments, permission slips, IEP input. Merged into course.ts.
export const EDUCATION_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-edu-early-01","level":"early","profession":"education","title":"The behavior email that circles","scenario":"A student pushed a classmate in line today and you need to email his parents tonight. Your draft opens with two paragraphs about how much you enjoy having him in class before mentioning what happened.","task":"Write the first two sentences of the email, leading with why you're writing.","tips":["Name the reason for the email in sentence one, calmly and factually.","Warmth can frame the message without hiding it.","Parents trust teachers who tell them things straight."],"focus":["clarity","structure"],"placeholder":"I'm writing because Marcus pushed a classmate in line today —"},
    {"id":"lead-edu-early-02","level":"early","profession":"education","title":"The yes the principal is waiting for","scenario":"Your principal emailed asking whether all 24 field trip permission slips are in before she confirms the buses. They are. Your reply draft starts with a recap of how you collected them.","task":"Write a 1-2 sentence reply that answers her question first.","tips":["Answer yes or no in the first few words.","She's holding a bus booking on your reply — don't make her hunt.","The collection story is optional detail, or cut it."],"focus":["concision","clarity"],"placeholder":"Yes — all 24 slips are in."},
    {"id":"lead-edu-early-03","level":"early","profession":"education","title":"The coverage request buried in apology","scenario":"You have a dentist appointment Thursday at 1pm and need your lead teacher to cover your last period. Your draft message spends three sentences apologizing for asking before naming the day and time.","task":"Write a message that puts the specific ask in the first sentence.","tips":["Lead with what you need: cover, Thursday, last period.","One brief thank-you beats three apologies.","Make it easy to answer yes or no."],"focus":["clarity","concision"],"placeholder":"Could you cover my last period this Thursday? I have a 1pm dental appointment."},
    {"id":"lead-edu-early-04","level":"early","profession":"education","title":"The early-dismissal announcement","scenario":"School dismisses two hours early next Friday for staff training. Your class newsletter draft mentions this in the fourth paragraph, after a recap of this week's science unit. Parents who skim will miss it and show up late.","task":"Write the newsletter's opening line so the schedule change comes first.","tips":["The information parents must act on goes first.","Recaps are nice-to-know; pickup times are need-to-know.","State the date and time plainly, no lead-up."],"focus":["structure","impact"],"placeholder":"Next Friday, June 12, school dismisses at 1:15 —"},
    {"id":"lead-edu-early-05","level":"early","profession":"education","title":"The projector ticket that rambles","scenario":"Your classroom projector died and you teach a slide-heavy lesson tomorrow at 9am. Your email to IT describes everything you tried — cables, restarts, a different laptop — before saying what you need and by when.","task":"Write a request that leads with the need and the deadline.","tips":["First sentence: what's broken and when you need it working.","Troubleshooting steps are helpful support — put them after.","A clear deadline lets IT triage you correctly."],"focus":["clarity","precision"],"placeholder":"My projector in Room 114 is dead and I need it working by 9am tomorrow —"},
    {"id":"lead-edu-early-06","level":"early","profession":"education","title":"The concern that hides in the update","scenario":"Your principal asked how your new student is settling in. The honest headline: he's stopped turning in work and you're worried. Your draft opens with three sentences about how friendly he is at recess.","task":"Write a 2-3 sentence update that leads with the concern.","tips":["Lead with the thing that needs attention.","Positives can follow — they're context, not the point.","Name what you're already doing or what you need from her."],"focus":["clarity","impact"]},
    {"id":"lead-edu-early-07","level":"early","profession":"education","title":"The permission slip reminder","scenario":"Eight families still haven't returned the museum trip slip, and the cutoff is Wednesday — no slip, no trip. Your reminder draft opens with a paragraph about how exciting the museum will be.","task":"Write a 2-sentence reminder that leads with the deadline and consequence.","tips":["Deadline and what happens without the slip go in sentence one.","Excitement about the trip is fine — after the action item.","Tell parents exactly what to send back and how."],"focus":["clarity","impact"],"placeholder":"Museum trip slips are due Wednesday — students without one can't attend."},
    {"id":"lead-edu-early-08","level":"early","profession":"education","title":"Good news, delivered late","scenario":"A student who struggled with reading all fall just scored above grade level on the winter assessment. You're emailing her parents, but your draft spends the first paragraph recapping the fall struggles.","task":"Write an email opening that leads with the good news.","tips":["Put the win in sentence one — let parents feel it immediately.","The fall backstory makes the win bigger, but it comes second.","Be specific about what she achieved."],"focus":["impact","clarity"],"placeholder":"Wonderful news: Amara's winter reading assessment came back above grade level."},
    {"id":"lead-edu-early-09","level":"early","profession":"education","title":"The mentor-time request","scenario":"You want 20 minutes with your mentor teacher to review Monday's observed lesson plan before you submit it. Your draft message meanders through how the planning has been going before getting to the ask.","task":"Write a message that leads with the request and the time frame.","tips":["Ask first: 20 minutes, before Friday, to review the plan.","Say what you want feedback on so she can prepare.","Vague asks get postponed; bounded asks get scheduled."],"focus":["clarity","concision"],"placeholder":"Could I get 20 minutes with you before Friday to review my observed lesson plan?"},
    {"id":"lead-edu-early-10","level":"early","profession":"education","title":"The sub plans that bury the essentials","scenario":"You're out sick tomorrow and writing plans for the substitute. The one thing that must happen: third period walks to the library at 10:15 for a scheduled visit. Your draft mentions it on page two.","task":"Write the opening lines of your sub plans, leading with the must-do item.","tips":["Put the one unmissable event at the very top, flagged clearly.","Routine instructions can follow in order.","Assume the sub reads the first five lines carefully and skims the rest."],"focus":["structure","precision"],"placeholder":"MOST IMPORTANT: Third period walks to the library at 10:15 —"},
    {"id":"lead-edu-early-11","level":"early","profession":"education","title":"The counselor referral that wanders","scenario":"You want the school counselor to check in with a student whose journal entries have turned dark this month. Your email drafts a long timeline of the semester before making the request.","task":"Rewrite the email so the request comes first, then the key evidence.","tips":["Lead with the ask: please check in with this student this week.","Give two or three specific observations as support.","Urgency should be readable in the first sentence."],"focus":["clarity","impact"]},
    {"id":"lead-edu-early-12","level":"early","profession":"education","title":"The training recap for the manager","scenario":"You're a new corporate trainer. The onboarding session you ran today finished on time with a 4.6/5 feedback score, and your manager asked for a quick recap. Your draft walks through the agenda hour by hour.","task":"Write a 2-3 sentence recap that leads with the outcome.","tips":["Headline first: delivered, on time, 4.6/5.","One notable detail or follow-up is enough.","The hour-by-hour agenda is what she already approved — skip it."],"focus":["concision","structure"],"placeholder":"Onboarding session delivered on time today — 4.6/5 average from 18 attendees."},
    {"id":"lead-edu-early-13","level":"early","profession":"education","title":"The recess report, status first","scenario":"You're a teaching assistant. A student tripped at recess, scraped her knee, saw the nurse, and is fine and back in class. You're messaging the classroom teacher, and your draft starts with the full story of the game that caused it.","task":"Write a message that leads with the current status: she's fine.","tips":["First words: who, what happened, and that she's okay now.","Teachers read injury messages braced for bad news — resolve that fast.","The play-by-play can follow briefly."],"focus":["clarity","structure"],"placeholder":"Naya scraped her knee at recess — the nurse cleaned it and she's fine, back in class."},
    {"id":"lead-edu-early-14","level":"early","profession":"education","title":"The conference scheduling email","scenario":"You need to schedule a conference with a parent about their son's math progress. You have three open slots next week. Your draft explains the whole progress picture before ever proposing a time.","task":"Write an email that leads with the meeting request and the three time options.","tips":["First line: I'd like to meet about Daniel's math progress — here are three times.","Save the detail for the meeting itself; one sentence of context is plenty.","Concrete options get faster replies than 'let me know your availability.'"],"focus":["clarity","concision"]},
    {"id":"lead-edu-early-15","level":"early","profession":"education","title":"Picture day moved","scenario":"The photographer rescheduled picture day from Tuesday to Thursday. Families plan outfits around this. Your class-app message drafts an explanation of why the photographer changed before stating the new date.","task":"Write a 1-2 sentence message that leads with the change.","tips":["New date first, old date second, reason last or not at all.","Parents need the action, not the photographer's logistics.","Keep it short enough to read in a notification preview."],"focus":["concision","clarity"],"placeholder":"Picture day has moved to Thursday, Oct 16 (was Tuesday)."},
    {"id":"lead-edu-early-16","level":"early","profession":"education","title":"The gradebook glitch before report cards","scenario":"The online gradebook is dropping some assignment scores, and report-card grades export Friday. Your email to the district tech team opens with a polite paragraph about understanding how busy they are.","task":"Write a request that leads with the problem and the Friday deadline.","tips":["Problem plus deadline in sentence one — that's the triage information.","Describe the symptom precisely: which scores, since when.","Courtesy is one clause, not a paragraph."],"focus":["clarity","precision"],"placeholder":"The gradebook is dropping assignment scores and report cards export Friday —"},
    {"id":"lead-edu-early-17","level":"early","profession":"education","title":"The pilot update at staff meeting","scenario":"You have 60 seconds at the staff meeting to update everyone on the reading-buddies pilot. The headline: participating students read 30% more minutes this month. Your notes start with how the pairings were organized.","task":"Write your opening two sentences, leading with the result.","tips":["Result first: what changed for students.","How it was organized only matters if someone asks.","End with the one thing you want from colleagues, if anything."],"focus":["impact","concision"],"placeholder":"One month in, reading-buddies students are reading 30% more minutes."},
    {"id":"lead-edu-early-18","level":"early","profession":"education","title":"The hazard report","scenario":"A window latch in your classroom is broken and the window swings open over a second-floor drop. You're emailing the principal and facilities. Your draft opens with when you first noticed something felt off.","task":"Write a report that leads with the hazard and the room.","tips":["Safety issues lead with what and where — no wind-up.","Say what you've done in the meantime (locked it, moved desks).","Ask for a specific response: repair timeline."],"focus":["clarity","impact"],"placeholder":"Safety issue in Room 114: the window latch is broken and it swings open —"},
    {"id":"lead-edu-early-19","level":"early","profession":"education","title":"The session that has to move","scenario":"You're a corporate trainer and a room conflict means Thursday's workshop must move to Friday morning. Your email to the client contact drafts a long explanation of the booking mix-up before proposing the new time.","task":"Write a 2-3 sentence email that leads with the change and the proposed new slot.","tips":["Lead with the new plan, not the problem's history.","One sentence of apology or explanation is enough.","End with the confirmation you need and by when."],"focus":["clarity","structure"]},
    {"id":"lead-edu-early-20","level":"early","profession":"education","title":"The duty swap","scenario":"You need to swap Wednesday lunch duty with a colleague because of an IEP meeting scheduled over your break. Your draft message walks through your whole week before asking.","task":"Write a message that leads with the swap request.","tips":["Ask in sentence one: swap Wednesday lunch duty?","Offer the return favor immediately — your Friday for their Wednesday.","Reason in one clause; colleagues don't need the calendar tour."],"focus":["concision","clarity"],"placeholder":"Could we swap lunch duties this week — your Wednesday for my Friday?"},
    {"id":"lead-edu-early-21","level":"early","profession":"education","title":"The missing-work email","scenario":"A student has six missing assignments and will fail the quarter if they aren't in by the 15th. Your email to his parents opens gently with how creative he is in class discussions, and the real message doesn't appear until paragraph three.","task":"Write an opening that states the situation and the deadline in the first two sentences.","tips":["Parents need the stakes and the date up front to act in time.","Kind and direct beats gentle and buried.","Follow with the specific list and how you'll help."],"focus":["clarity","impact"],"placeholder":"I want to flag something urgent: Jayden has six missing assignments, and"},
    {"id":"lead-edu-early-22","level":"early","profession":"education","title":"The answer-key correction","scenario":"You spotted an error in the shared quiz answer key your grade team uses — question 7's answer is wrong, and two colleagues grade tonight. Your message to the team thread starts by explaining how you happened to notice it.","task":"Write a message that leads with the correction.","tips":["The fix goes first: question 7's answer is C, not B.","People skim team threads — the correction must be un-missable.","How you found it is trivia; cut or compress it."],"focus":["clarity","precision"],"placeholder":"Correction to the unit 4 quiz key: question 7 is C, not B."},
    {"id":"lead-edu-early-23","level":"early","profession":"education","title":"The accommodation gap","scenario":"A student's support plan guarantees extended test time, but the schedule gives you no way to provide it during Friday's exam block. You're emailing the special-education coordinator, and your draft buries the ask under the scheduling details.","task":"Write an email that leads with what you need from the coordinator.","tips":["Lead with the ask: help arranging extended time for Friday's exam.","Then the constraint, in one or two sentences.","Flag the date early — this has a deadline."],"focus":["clarity","structure"]},
    {"id":"lead-edu-early-24","level":"early","profession":"education","title":"The late bus message","scenario":"Your field trip bus is stuck in traffic and you'll be back 40 minutes after dismissal. Parents are already gathering at pickup. You're sending a message through the class app from the bus.","task":"Write a 1-2 sentence message that gives parents the essential facts first.","tips":["New arrival time first, reason second.","Say every student is safe and accounted for.","Short enough to read at a glance in the pickup line."],"focus":["clarity","concision"],"placeholder":"Our bus is delayed in traffic — new arrival time is 3:55. All students are safe"},
    {"id":"lead-edu-early-25","level":"early","profession":"education","title":"The supply request","scenario":"You need $180 for a classroom set of calculators before the measurement unit starts in three weeks. Your email to the principal opens with a long description of the unit's learning goals.","task":"Write a request that leads with the amount, the item, and the date needed.","tips":["First sentence: what, how much, by when.","One sentence of justification — tie it to student need.","Make approving it a 30-second decision."],"focus":["clarity","precision"],"placeholder":"Request: $180 for a class set of calculators, needed by March 2 for the measurement unit."}
  ],
  "start-with-the-audience": [
    {"id":"audience-edu-early-01","level":"early","profession":"education","title":"Below benchmark, in plain words","scenario":"A reading assessment flags a student as 'two levels below benchmark with weak decoding.' You're emailing his parents, who aren't educators. Your draft uses the assessment's exact language.","task":"Rewrite the key sentence so a parent understands what it means and what happens next.","tips":["Translate the label into what their child can and can't yet do.","Say what the school will do and what parents can do at home.","Jargon reads as either alarming or meaningless — plain words read as care."],"focus":["audience","clarity"],"placeholder":"Right now, Eli reads comfortably at about a first-grade level, and"},
    {"id":"audience-edu-early-02","level":"early","profession":"education","title":"Instructions third graders can follow","scenario":"You wrote lab-station instructions for your third graders: 'Rotate stations upon completion of each task, ensuring materials are returned to their original configuration.' Half the class just stood there.","task":"Rewrite the instructions in words an eight-year-old follows on the first read.","tips":["Short sentences, one action each, in the order they happen.","Use words kids say: 'put back,' not 'return to original configuration.'","Read it aloud — if it sounds like a memo, it fails."],"focus":["audience","clarity"],"placeholder":"1. Finish your station. 2. Put everything back where you found it. 3."},
    {"id":"audience-edu-early-03","level":"early","profession":"education","title":"The curriculum letter without edu-speak","scenario":"Your school is adopting a new math program, and your letter home drafts sentences like 'We're shifting to a conceptual, discourse-rich approach emphasizing formative assessment and differentiation.' Parents just want to know what changes for their kid.","task":"Write 2-3 sentences explaining the change in terms of what parents will notice.","tips":["Describe what homework and class time will look like, concretely.","Cut every term you learned in a PD session.","Answer the parent's real question: is my child going to be okay?"],"focus":["audience","clarity"]},
    {"id":"audience-edu-early-04","level":"early","profession":"education","title":"What the principal actually reads for","scenario":"Your principal asked for a paragraph on how your intervention group is going. Your draft lists the activities you ran each week. She reads updates for one thing: are students progressing, and do you need anything.","task":"Rewrite the update in 2-3 sentences aimed at what she needs to know.","tips":["Lead with progress against the goal, not the activity list.","Flag anything you need from her while you have her attention.","Activities are how; she's reading for whether."],"focus":["audience","impact"],"placeholder":"Four of my six intervention students have moved up a reading level since January."},
    {"id":"audience-edu-early-05","level":"early","profession":"education","title":"The accommodation note for the sub","scenario":"A student in your class has a support plan: he needs movement breaks and written directions. Your sub-plan note says 'Follow Aiden's IEP accommodations per his 504.' The substitute has never met him and won't see the plan.","task":"Write 2-3 sentences telling the sub exactly what to do for this student.","tips":["The sub needs behaviors and actions, not document names.","Say what it looks like when he needs a break and what to offer.","Write for someone with zero context and ten seconds to read."],"focus":["audience","precision"],"placeholder":"Aiden (red glasses, front row) needs to move every 20 minutes or so —"},
    {"id":"audience-edu-early-06","level":"early","profession":"education","title":"Compliance training for a skeptical room","scenario":"You're a new corporate trainer opening a mandatory data-privacy session for the sales team. Your draft opening explains the regulation's history. The salespeople in the room care about one thing: what this has to do with hitting their number.","task":"Write an opening (2-3 sentences) that hooks this audience through their own stakes.","tips":["Start from their world: deals, clients, commissions — not the regulation.","One concrete story of a deal lost to a privacy mistake beats ten rules.","Earn attention first; deliver requirements second."],"focus":["audience","impact"]},
    {"id":"audience-edu-early-07","level":"early","profession":"education","title":"The test-score letter","scenario":"State test results went home with a dense score report. You're writing the cover note for your class. Your draft explains scale scores and performance bands. Most parents will read three sentences on their phone.","task":"Write a 3-sentence cover note that tells parents what to look at and what it means.","tips":["Point them to the one number or label that matters and decode it.","Say what the school does with the score — and what it doesn't decide.","Invite questions through a channel you can actually manage."],"focus":["audience","concision"],"placeholder":"The number to look at is the performance level on page 1 —"},
    {"id":"audience-edu-early-08","level":"early","profession":"education","title":"The newsletter for phone-skimmers","scenario":"Your weekly newsletter is a beautiful three-paragraph essay about the week. Open rates say parents read it on phones, at pickup, in about 15 seconds. Buried inside: a due date, a needed supply, and a schedule change.","task":"Rewrite the newsletter's top section as a skimmable format that surfaces the three action items.","tips":["Action items first, labeled, one line each.","The narrative of the week can live below for those who scroll.","Bold the dates. Assume 15 seconds, not 3 minutes."],"focus":["audience","structure"]},
    {"id":"audience-edu-early-09","level":"early","profession":"education","title":"The behavior plan, explained to the kid","scenario":"You and the counselor built a behavior plan for a fourth grader: a points chart, break passes, and a daily check-out. Now you have to explain it to him. Your draft sounds like the plan document.","task":"Write 3-4 sentences explaining the plan to the student in words that feel fair, not punitive.","tips":["Frame it as a tool that helps him, not a system that watches him.","Use his language: 'when you feel like you need a break' not 'self-regulation.'","Tell him the part where he wins."],"focus":["audience","clarity"],"placeholder":"You know how some days it's hard to stay at your seat? We made something to help —"},
    {"id":"audience-edu-early-10","level":"early","profession":"education","title":"Plain language for every family","scenario":"Several families in your class speak English as a second language. Your field-trip letter includes phrases like 'in lieu of,' 'weather permitting,' and 'remit payment.' The information matters: date, cost, what to pack.","task":"Rewrite the key details in plain language any family can follow.","tips":["Short sentences, common words, one fact per line.","'Send $5' beats 'remit payment'; 'if it rains, we stay at school' beats 'weather permitting.'","Plain language isn't dumbed down — it's the version everyone gets right."],"focus":["audience","clarity"],"placeholder":"The trip is Friday, May 3. Please send: $5, a packed lunch, and"},
    {"id":"audience-edu-early-11","level":"early","profession":"education","title":"The help request a veteran can answer","scenario":"Your classroom transitions are chaos and you want advice from the veteran teacher next door. Your draft message tells the whole story of your week. She has four minutes between classes and twenty years of answers — if you ask precisely.","task":"Write a request that gives her exactly what she needs to give you one useful answer.","tips":["Name the specific moment: the transition from carpet to desks.","Say what you've tried, in one sentence, so she skips it.","Ask for one thing: her go-to move, or five minutes watching her do it."],"focus":["audience","concision"],"placeholder":"Can I ask your go-to move for one thing? My carpet-to-desks transition loses 5 minutes"},
    {"id":"audience-edu-early-12","level":"early","profession":"education","title":"Phonics homework, decoded","scenario":"You're sending home a phonics practice sheet with a note that says 'Practice segmenting and blending CVC words with your child.' You can already picture parents googling 'CVC.'","task":"Rewrite the note so any parent knows exactly what to do for five minutes tonight.","tips":["Describe the activity as actions: say the word slowly, stretch the sounds.","Give one worked example right in the note.","The test: could a tired parent do this at 7pm with zero prep?"],"focus":["audience","clarity"],"placeholder":"Tonight, pick three words from the sheet. Say each one slowly —"},
    {"id":"audience-edu-early-13","level":"early","profession":"education","title":"One email, one audience","scenario":"A student had a rough day — a shouting outburst, then a good recovery. You drafted one email and addressed it to both his parents and your principal. Halfway through you realize the two readers need different things.","task":"Decide who the primary audience is and write the 2-3 sentence version for that reader.","tips":["Parents need what happened and what you're doing; the principal needs pattern and support-ask.","One message aimed at two audiences serves neither.","Write the second message separately — don't CC your way out."],"focus":["audience","structure"]},
    {"id":"audience-edu-early-14","level":"early","profession":"education","title":"Login instructions for grandma","scenario":"A student lives with her grandmother, who wants to check the homework portal but 'isn't good with computers.' The school's standard instructions reference SSO, browser cache, and the district portal. You're writing her a personal note.","task":"Write step-by-step instructions a first-time computer user can follow alone.","tips":["Number every step; each step is one tap or one click.","Name what she'll see on screen so she knows she's on track.","Include the rescue line: a phone number if she gets stuck."],"focus":["audience","precision"]},
    {"id":"audience-edu-early-15","level":"early","profession":"education","title":"The small-group debrief","scenario":"You're a teaching assistant who just ran a reading group while the teacher taught the main lesson. She has 90 seconds between periods and needs to know how it went. Your instinct is to recount all 20 minutes.","task":"Write the 2-3 sentence debrief that gives her exactly what she'd act on.","tips":["Lead with the exception: who struggled, who surprised you.","'Everyone else on track' covers the rest in four words.","Tell her the one thing to know before tomorrow's group."],"focus":["audience","concision"],"placeholder":"Quick read-group debrief: Mia guessed at every long word today —"},
    {"id":"audience-edu-early-16","level":"early","profession":"education","title":"The feedback summary HR will forward","scenario":"You're a corporate trainer summarizing course feedback for the HR director. Your draft details every comment. She'll spend 60 seconds on it and forward it to her VP — so it needs to survive being read by someone with even less context.","task":"Write a 3-sentence summary: the verdict, the evidence, the one recommended change.","tips":["Write for the forward: no insider references, no unexplained acronyms.","One number (average score, completion) anchors the verdict.","End with the action you recommend, not just observations."],"focus":["audience","structure"],"placeholder":"The negotiation workshop scored 4.5/5 across 32 attendees —"},
    {"id":"audience-edu-early-17","level":"early","profession":"education","title":"Chaperone instructions that survive the bus","scenario":"Four parent chaperones join Friday's zoo trip. Your instruction sheet is a page of policy language from the district handbook. On the day, they'll need about six facts: their group, the schedule, the rules, and what to do if a kid is hurt or missing.","task":"Write the six-line version a chaperone can use from their pocket.","tips":["Lead with their group list and your cell number.","One line per scenario: injury, missing child, bathroom trips.","Policy language protects the district; your sheet has to work at the zoo."],"focus":["audience","precision"]},
    {"id":"audience-edu-early-18","level":"early","profession":"education","title":"Standards-based grades for letter-grade parents","scenario":"Your school reports '3 - Meeting standard' instead of letter grades, and every conference starts with 'so is a 3 like a B?' You're writing the explanation for your class website.","task":"Write 3-4 sentences that explain the system through the question parents are actually asking.","tips":["Meet the letter-grade mental model head-on instead of ignoring it.","Explain what a 3 tells them that a B doesn't.","Reassure on the real worry: college, fairness, is my kid behind."],"focus":["audience","clarity"],"placeholder":"The honest answer: a 3 isn't a B — it means your child can do"},
    {"id":"audience-edu-early-19","level":"early","profession":"education","title":"The assembly announcement, for kids","scenario":"You have to announce the new hallway expectations to your class after an all-staff email full of phrases like 'level-zero voice' and 'expected behaviors matrix.' Sixth graders will tune that out in four seconds.","task":"Write how you'd say it to your class in 3-4 spoken sentences.","tips":["Say what to do, not what framework it comes from.","Give the reason a kid respects: real, brief, not preachy.","End by checking they got it, not by repeating it."],"focus":["audience","clarity"]},
    {"id":"audience-edu-early-20","level":"early","profession":"education","title":"The referral the counselor can act on","scenario":"You're worried about a student — withdrawn for three weeks, sleeping in class, stopped eating lunch with friends. Your referral note to the counselor says 'having a hard time lately.' She triages dozens of these.","task":"Rewrite the referral with the specifics that let her prioritize correctly.","tips":["Give the observable changes and the time frame.","Say what you've tried and how the student responded.","Vague referrals sink in the pile; specific ones move up."],"focus":["audience","precision"],"placeholder":"Referral for Sam T., 6th grade: over the past 3 weeks he has"},
    {"id":"audience-edu-early-21","level":"early","profession":"education","title":"The syllabus paragraph students skip","scenario":"Your ninth-grade syllabus late-work policy is a paragraph of legalistic prose copied from a colleague. Students sign it without reading. The policy itself is simple: 10% off per day, three days max, then a conversation.","task":"Rewrite the policy in three lines a ninth grader actually reads and remembers.","tips":["Write to the student, not to a hypothetical auditor.","Numbers and days, not 'academic penalties may apply.'","If they can't repeat it back, it isn't a policy — it's a paragraph."],"focus":["audience","concision"],"placeholder":"Late work: minus 10% per day, up to 3 days."},
    {"id":"audience-edu-early-22","level":"early","profession":"education","title":"The donation ask to a local business","scenario":"You're asking the hardware store downtown to donate supplies for a class garden project. Your draft reads like a lesson plan, full of learning objectives. The owner cares about cost, effort, and what it does for the neighborhood.","task":"Write a 3-4 sentence ask in the owner's terms.","tips":["Lead with the concrete ask: what items, roughly what value.","Frame the payoff in their world: local kids, visible project, community goodwill.","Make saying yes effortless: you'll pick up, any brand works."],"focus":["audience","impact"]},
    {"id":"audience-edu-early-23","level":"early","profession":"education","title":"Make-up work for the stressed parent","scenario":"A student was out sick four days, and her mother emailed at 11pm, overwhelmed, asking how her daughter can possibly catch up. Your make-up policy is reasonable, but reciting it will read as cold.","task":"Write a reply that gives this parent the plan in a way that lowers her stress.","tips":["Lead with reassurance that's true: she has time, and you have a plan.","Then the plan, small and ordered: start with these two things.","Cut anything that sounds like policy citation."],"focus":["audience","clarity"],"placeholder":"Please don't worry — Sofia has a full week to catch up, and we'll do it in steps."},
    {"id":"audience-edu-early-24","level":"early","profession":"education","title":"The pre-course email people actually read","scenario":"You're a corporate trainer sending the pre-work email for next week's workshop. Your draft describes the course design and learning outcomes. Attendees will skim it for one thing: what do I have to do before Tuesday?","task":"Write the email so the required actions are impossible to miss.","tips":["Actions first, labeled and bulleted: complete this, bring that.","Time-cost honesty ('20 minutes') raises completion rates.","Course philosophy goes at the bottom or nowhere."],"focus":["audience","structure"],"placeholder":"Before Tuesday, please do two things (about 20 minutes total):"},
    {"id":"audience-edu-early-25","level":"early","profession":"education","title":"The pickup-line procedure","scenario":"The school changed its dismissal pickup procedure, and the official notice is 400 words of traffic-flow description. You're summarizing it for your class families — who will process it while driving into the lot at 2:55.","task":"Write the 3-line version for the parent in the car.","tips":["Sequence it as the driver experiences it: enter here, show this, stop there.","One detail per line; no paragraph survives a car line.","Name the one change from the old routine explicitly."],"focus":["audience","concision"]}
  ],
  "structure-that-carries": [
    {"id":"structure-edu-early-01","level":"early","profession":"education","title":"Back-to-school night in three buckets","scenario":"You have ten minutes to address parents at back-to-school night. Your notes are a list of nineteen things: curriculum, homework, snacks, birthdays, the reading program, your email policy. Parents will remember almost none of it.","task":"Organize the talk under one governing idea and at most three buckets — name them.","tips":["One sentence that carries the whole talk: what you want them to leave believing.","Group the nineteen items under ~3 headers parents can recall at dinner.","Anything that doesn't fit a bucket goes in the handout, not the talk."],"focus":["structure","audience"],"placeholder":"Governing idea: your child will be known, challenged, and safe here. Bucket 1:"},
    {"id":"structure-edu-early-02","level":"early","profession":"education","title":"Nine reminders, grouped","scenario":"Your newsletter draft ends with nine loose reminders: library books Tuesday, picture money, spirit-wear Friday, conference sign-ups, box tops, the food drive, early dismissal, permission slips, and volunteering. It reads like a junk drawer.","task":"Group the nine reminders into 2-3 labeled clusters and write the headers.","tips":["Group by what the parent must do: send something, mark a date, sign up.","A label like 'Send to school this week' does half the reading for them.","Order clusters by urgency, most time-sensitive first."],"focus":["structure","clarity"],"placeholder":"SEND THIS WEEK: library books (Tue), picture money"},
    {"id":"structure-edu-early-03","level":"early","profession":"education","title":"SCQA for the classroom library","scenario":"You want the principal to approve $300 for classroom library books. You have facts everywhere: kids share tattered copies, your class loves reading time, the school goal is literacy growth. You need a shape for the pitch.","task":"Write the pitch as four sentences: Situation, Complication, Question, Answer.","tips":["Situation: the shared goal she already owns (literacy growth).","Complication: what's blocking it in your room, concretely.","Answer: the specific ask — amount, what it buys, what it changes."],"focus":["structure","impact"],"placeholder":"Our school goal is 10% reading growth this year. In my room,"},
    {"id":"structure-edu-early-04","level":"early","profession":"education","title":"PREP for 'How's my kid doing?'","scenario":"Every conference opens with the same question: 'So, how's she doing?' Last time you rambled through anecdotes for five minutes. You want a repeatable spoken structure: Point, Reason, Example, Point.","task":"Write a PREP-structured spoken answer for one student, four sentences.","tips":["Point: the one-sentence honest headline of how she's doing.","Reason and Example: the evidence — a skill, a grade, a moment.","Restate the point with the path forward attached."],"focus":["structure","clarity"],"placeholder":"Maya is doing well overall, with one thing to work on. Her"},
    {"id":"structure-edu-early-05","level":"early","profession":"education","title":"The project email parents can navigate","scenario":"The state-report project has three due dates, a materials list, an in-class portion, and optional parent help. Your draft email explains it all in one long paragraph. Parents will email you questions the paragraph already answers.","task":"Restructure the email with headers so a parent can find any fact in five seconds.","tips":["Sections match parent questions: When is it due? What do we send? How can I help?","Dates get their own labeled lines, never buried mid-sentence.","A findable email prevents twenty duplicate questions."],"focus":["structure","audience"]},
    {"id":"structure-edu-early-06","level":"early","profession":"education","title":"Sub plans with a spine","scenario":"Your sub plans are a stream-of-consciousness page: schedule mixed with behavior notes mixed with where the pencils live. A substitute needs to run your room from this in real time.","task":"Reorganize the plans into labeled sections and write the section headers in order.","tips":["Time-ordered schedule first — that's the document they live in.","Separate sections for: key students, routines, emergencies, where things are.","The test: can a stranger find 'what do I do at 10:15' in three seconds?"],"focus":["structure","precision"],"placeholder":"1) TODAY'S SCHEDULE (times + what to do) 2)"},
    {"id":"structure-edu-early-07","level":"early","profession":"education","title":"The quiz-calendar proposal","scenario":"At the grade-team meeting you're proposing that the four teachers stagger quiz days so students don't get three quizzes on Fridays. You have reasons, examples, and a suggested calendar — currently in no particular order.","task":"Structure the proposal: one governing sentence, then three supporting points in order.","tips":["Governing sentence carries the whole ask: stagger quiz days across the week.","Order points by what moves colleagues: student benefit, low effort, easy pilot.","End with the smallest yes: try it for one unit."],"focus":["structure","impact"]},
    {"id":"structure-edu-early-08","level":"early","profession":"education","title":"The one-page course outline","scenario":"You're a corporate trainer and your manager wants a one-page outline of your proposed time-management workshop before pitching it internally. Your draft is a topic list with no hierarchy — she can't tell the big ideas from the details.","task":"Write the outline's skeleton: workshop goal, 3 sections, and what each section delivers.","tips":["The goal at top is a change in behavior, not a list of topics.","Three sections, each named for what participants can do afterward.","Details nest under sections; nothing floats free."],"focus":["structure","clarity"],"placeholder":"Goal: participants leave running their week from a priority list, not their inbox. Section 1:"},
    {"id":"structure-edu-early-09","level":"early","profession":"education","title":"IEP input in three themes","scenario":"You have a page of scattered observations for a student's IEP meeting: he loses his place reading aloud, avoids writing tasks, thrives with sentence starters, rushes multi-step directions, works well in pairs. The team gets five minutes of your input.","task":"Group your observations into 2-3 named themes and state each theme in one sentence.","tips":["Themes are patterns ('multi-step tasks break down'), not lists of incidents.","Pair every struggle with the support that's worked — the team needs both.","Three themes survive a meeting; twelve observations don't."],"focus":["structure","precision"],"placeholder":"Theme 1 — multi-step tasks: directions with 3+ steps break down unless"},
    {"id":"structure-edu-early-10","level":"early","profession":"education","title":"Five questions, one clean reply","scenario":"A parent's email asks five things in one breathless paragraph: the field trip cost, the book report rubric, whether her son can retake the quiz, his reading level, and your tutoring recommendation. Answering in a paragraph of your own will lose half of it.","task":"Structure the reply so each question gets a clearly separated answer.","tips":["Mirror her questions back as labels, then answer under each.","One-line answers where one line is enough.","A structured reply signals every question was heard — that's half the reassurance."],"focus":["structure","clarity"]},
    {"id":"structure-edu-early-11","level":"early","profession":"education","title":"The incident report that holds up","scenario":"Two students fought at recess and you're writing the incident report. Your draft mixes what you saw, what other kids said, what you did, and what should happen next, all interleaved.","task":"Restructure the report into ordered sections: what happened, actions taken, follow-up needed.","tips":["Separate what you directly saw from what was reported to you.","Time-order the events; label the actions you took as you took them.","The report may be read months later by someone with no context — structure is its memory."],"focus":["structure","precision"],"placeholder":"What I observed (11:40, blacktop):"},
    {"id":"structure-edu-early-12","level":"early","profession":"education","title":"PREP on the spot at staff meeting","scenario":"The principal asks, in front of the staff, 'You've been piloting the new phonics program — is it worth expanding?' You have thirty seconds and a strong view. Rambling here costs credibility.","task":"Write your spoken answer in PREP form: Point, Reason, Example, Point.","tips":["Answer the question in sentence one: yes, expand it — or not yet.","One reason and one concrete example carry more than five of each.","Land the plane: restate the point and stop talking."],"focus":["structure","concision"],"placeholder":"Yes — I'd expand it. My decoding group has"},
    {"id":"structure-edu-early-13","level":"early","profession":"education","title":"Field trip logistics: before, day-of, after","scenario":"Your aquarium trip email covers money, waivers, bus times, lunch, chaperone assignments, dress code, and the follow-up assignment — currently in the order you thought of them.","task":"Reorganize the email into three time-based sections and write the three headers with their items.","tips":["Before / On the day / After maps to how parents will use it.","Within each section, order by deadline.","Time-based structure means nobody reads the whole email twice."],"focus":["structure","clarity"]},
    {"id":"structure-edu-early-14","level":"early","profession":"education","title":"Essay feedback with one governing point","scenario":"You're writing feedback on a seventh grader's essay. Your margin notes flag eleven different issues. If your summary comment lists all eleven, he'll fix the commas and miss the real problem: the essay has no thesis.","task":"Write a summary comment with one governing point and at most three supporting fixes.","tips":["Lead with the one change that would improve the essay most.","Choose the three fixes that serve that point; let the rest go this round.","Feedback structured around one idea gets acted on; lists get skimmed."],"focus":["structure","impact"],"placeholder":"The big one: your essay needs one sentence that says what you're arguing."},
    {"id":"structure-edu-early-15","level":"early","profession":"education","title":"SCQA for aide time","scenario":"You want to ask the principal for 30 minutes of daily classroom-aide time. Your raw material: two students need one-on-one reading support, you can't leave the other 22 unattended, and intervention slots are full until spring.","task":"Write the request as SCQA in four sentences.","tips":["Situation: the goal or expectation already agreed on.","Complication: the gap that makes it impossible right now.","The Answer names the exact resource: 30 minutes, daily, when."],"focus":["structure","clarity"]},
    {"id":"structure-edu-early-16","level":"early","profession":"education","title":"Assessment results, pyramid-style","scenario":"You're summarizing your class's math assessment for the principal: 18 of 26 passed, fractions were the weak strand, your two newcomers need decoding support before word problems, and you're planning a re-teach week. Right now it's a data dump.","task":"Write the summary with the main takeaway on top and details nested beneath.","tips":["Top sentence: the one thing she should conclude from the data.","Group details as evidence under that conclusion, not as a second list.","End with your plan — data without a plan reads as a problem handed upward."],"focus":["structure","precision"],"placeholder":"Bottom line: the class is on track except fractions, and I have a re-teach plan."},
    {"id":"structure-edu-early-17","level":"early","profession":"education","title":"The pattern, not the pile","scenario":"You've emailed the counselor three separate times about the same student: once about crying at drop-off, once about a lunchroom conflict, once about an anxious note in her journal. Each email was one incident. Nobody has seen the whole picture.","task":"Write the message that assembles the incidents into one structured pattern with a clear ask.","tips":["Open with the pattern statement, then list the incidents as evidence with dates.","Three data points in one message outweigh three scattered emails.","Close with the specific next step you're asking for."],"focus":["structure","impact"],"placeholder":"I want to connect three things about Lena that together concern me more than any one did."},
    {"id":"structure-edu-early-18","level":"early","profession":"education","title":"The post-training report","scenario":"You're a corporate trainer writing the wrap-up report for a three-session onboarding series. You have attendance numbers, quiz scores, feedback quotes, and ideas for next time — and a blank page.","task":"Structure the report: one-sentence takeaway, three labeled sections, one recommendation.","tips":["The takeaway is a verdict, not a topic: 'ready to scale' or 'needs revision.'","Sections group evidence by type: participation, learning, experience.","One recommendation with a next step beats five loose ideas."],"focus":["structure","concision"]},
    {"id":"structure-edu-early-19","level":"early","profession":"education","title":"A template for the weekly update","scenario":"Your weekly parent update takes you 45 minutes because you start from scratch every Friday, and parents say they can never find the dates. You want a recurring structure both you and they can rely on.","task":"Design the update's repeating skeleton: 3 fixed sections with one-line descriptions of what goes in each.","tips":["Fixed sections mean parents learn where to look — and you stop redesigning.","Put 'dates and actions' as its own section, always in the same place.","Keep one flexible section for the story of the week."],"focus":["structure","audience"],"placeholder":"Section 1 — DATES & TO-DOS: every deadline, one line each. Section 2 —"},
    {"id":"structure-edu-early-20","level":"early","profession":"education","title":"Why the grade is a B","scenario":"A parent has asked you to explain her daughter's B in social studies. You have the gradebook open: strong tests, missing homework, a weak project. Read aloud as-is, it's just numbers. You need it to carry a conclusion.","task":"Write the explanation as one governing sentence supported by the three evidence points.","tips":["Governing sentence: what the B means about her learning, not just arithmetic.","Attach each number to what it shows she can or can't do yet.","End with what would move it — parents hear a path, not a verdict."],"focus":["structure","clarity"],"placeholder":"Rosa's B reflects strong understanding pulled down by incomplete practice —"},
    {"id":"structure-edu-early-21","level":"early","profession":"education","title":"Twelve questions into an FAQ","scenario":"After open house you received twelve emailed questions — about homework, tech, snacks, birthdays, pickup, grading, tutoring. You're building a class FAQ so you never answer them one by one again.","task":"Group the twelve topics into 3-4 named categories a parent would look under.","tips":["Categories follow parent intent: Daily routines, Schoolwork and grades, Events and celebrations.","Test each label: would a parent guess their question lives there?","Order categories by how often the questions come up."],"focus":["structure","audience"]},
    {"id":"structure-edu-early-22","level":"early","profession":"education","title":"The club proposal","scenario":"You want to start a Wednesday chess club and need admin approval. Your notes: kids keep asking, you'll supervise, the library is free at lunch, it needs no budget, a parent offered to donate sets. It's persuasive material with no shape.","task":"Write the proposal as SCQA, ending with the specific approval you need.","tips":["Situation and Complication set up why this, why now.","The Answer is the full ask in one sentence: what, where, when, supervised by whom.","Pre-answer the admin's first question — cost and liability — inside the structure."],"focus":["structure","impact"]},
    {"id":"structure-edu-early-23","level":"early","profession":"education","title":"The interview answer with bones","scenario":"You're prepping for a permanent-position interview. The guaranteed question: 'How do you handle classroom management?' Your practice answers wander through stories and trail off.","task":"Write a PREP-structured answer you could deliver in 45 seconds.","tips":["Point: your management philosophy in one sentence.","Example: one specific moment where it worked — named routine, real result.","Return to the point so the answer ends on purpose, not on fade-out."],"focus":["structure","concision"],"placeholder":"My approach is that routines prevent most problems before they start."},
    {"id":"structure-edu-early-24","level":"early","profession":"education","title":"Handoff notes for next year's teacher","scenario":"It's June and you're writing handoff notes about your class for next year's teacher. Your draft is a paragraph per student — 26 paragraphs nobody will read in September. The reader needs patterns first, individuals second.","task":"Design the handoff's structure: what comes first, what's grouped, what's per-student.","tips":["Open with class-level patterns: dynamics, groupings that work, whole-class needs.","Then flag only the students who need day-one awareness, with one line each.","Full detail per student goes in an appendix the reader can pull when needed."],"focus":["structure","audience"]},
    {"id":"structure-edu-early-25","level":"early","profession":"education","title":"The apology with a plan","scenario":"You fell two weeks behind on grading essays and parents have noticed the empty gradebook. You're writing the class email. It needs three moving parts — acknowledgment, plan, prevention — and your draft jumbles them.","task":"Write the email in three ordered moves: own it, the catch-up plan with dates, what changes going forward.","tips":["Own it in one plain sentence — no excuse woven in.","The plan carries the email: which grades post when.","One sentence on prevention; more starts to sound defensive."],"focus":["structure","clarity"],"placeholder":"You're right that essay grades have been slow to post, and that's on me. Here's the plan:"}
  ],
  "cut-to-the-bone": [
    {"id":"concise-edu-early-01","level":"early","profession":"education","title":"'Just wanted to reach out'","scenario":"Your email to a parent begins: 'I just wanted to quickly reach out and touch base regarding a small incident that occurred today that I thought you might want to be aware of.' Thirty words in, nothing has been said.","task":"Rewrite the opening in one direct sentence.","tips":["'Just,' 'quickly,' 'touch base,' 'reach out' — all deletable.","Say the thing: what happened, in plain words.","Directness reads as respect for the parent's time, not coldness."],"focus":["concision","clarity"],"placeholder":"I want to tell you about something that happened at lunch today."},
    {"id":"concise-edu-early-02","level":"early","profession":"education","title":"The newsletter paragraph, halved","scenario":"Your newsletter paragraph runs 110 words: 'This week we have been continuing our exploration of the fascinating world of fractions. The students have been working very hard on developing their understanding...' Parents skim past it.","task":"Rewrite the paragraph at half the length without losing information.","tips":["Cut ceremonial phrases: 'continuing our exploration of the fascinating world of.'","'Students learned to compare fractions' does the work of twenty words.","Keep the one detail a parent might mention at dinner."],"focus":["concision","audience"],"placeholder":"This week: comparing fractions. Ask your child to"},
    {"id":"concise-edu-early-03","level":"early","profession":"education","title":"'Sorry to bother you' to the principal","scenario":"Your request to the principal opens: 'I'm so sorry to bother you, I know how incredibly busy you are, and this is probably a silly question, but I was wondering if it might be possible to...' The ask is one sentence; the apology is three.","task":"Rewrite the request with the apologetic scaffolding removed.","tips":["Cut every pre-apology — the request earns its own place.","'Could I' or 'I'd like to' starts the sentence that matters.","Self-deprecation trains readers to discount you."],"focus":["concision","impact"],"placeholder":"Could I move my planning period on Thursdays this month?"},
    {"id":"concise-edu-early-04","level":"early","profession":"education","title":"The 60-word report-card comment","scenario":"Your report-card comment reads: 'Jamal is a very enthusiastic learner who has been making some really wonderful progress in many areas of his mathematical development this quarter, though there remain some areas where continued growth would be beneficial.' It says almost nothing in 60 words.","task":"Rewrite it in 25 words that say something specific.","tips":["One strength with evidence, one growth area with a next step.","Cut intensifiers: 'very,' 'really,' 'wonderful' carry no information.","A parent should learn something they didn't know."],"focus":["concision","precision"],"placeholder":"Jamal multiplies fluently and enjoys math games. Next: word problems —"},
    {"id":"concise-edu-early-05","level":"early","profession":"education","title":"The permission slip nobody finishes","scenario":"Your permission slip instructions run eight sentences, including 'Please be advised that students will be expected to bring with them a lunch that does not require refrigeration.' Completion rates show parents give up partway.","task":"Rewrite the instructions as the shortest complete version.","tips":["'Pack a lunch (no fridge available)' — six words, same meaning.","One line per required item; cut everything advisory.","Every extra sentence costs you returned slips."],"focus":["concision","clarity"]},
    {"id":"concise-edu-early-06","level":"early","profession":"education","title":"'As mentioned in my previous email'","scenario":"Your follow-up to a parent starts: 'As I mentioned in my previous email dated October 3rd, and as per the classroom policy I outlined at back-to-school night, I am writing to follow up once again regarding...' You're citing yourself instead of communicating.","task":"Rewrite the follow-up without the meta-commentary.","tips":["References to past communications are throat-clearing — cut them.","Just make the request again, cleanly, with the new deadline.","If the paper trail matters, it exists in the thread; you don't need to narrate it."],"focus":["concision","clarity"],"placeholder":"Reading logs are due Friday — Marcus still needs to turn in weeks 2 and 3."},
    {"id":"concise-edu-early-07","level":"early","profession":"education","title":"Classroom rules, poster-length","scenario":"Your draft classroom expectations read like a contract: 'Students are expected to demonstrate respect toward their peers and teachers at all times by engaging in active listening behaviors.' Five rules, ninety words. It's going on a poster.","task":"Rewrite the five rules at poster length — a few words each.","tips":["Rules kids can chant: 'Listen when others speak.'","Verbs first, conditions cut.","If a rule needs a subordinate clause, it's two rules or none."],"focus":["concision","audience"],"placeholder":"1. Listen when others talk. 2."},
    {"id":"concise-edu-early-08","level":"early","profession":"education","title":"The nominalization habit","scenario":"Your proposal to the principal says: 'The implementation of a morning check-in system would result in the reduction of behavioral disruptions and an improvement in the utilization of instructional time.' Every verb has been buried in a noun.","task":"Rewrite the sentence with people doing actions.","tips":["'Implementation of' → 'if we start'; 'reduction of' → 'fewer.'","Find who does what: check-ins calm mornings; students settle faster.","Verbs make the same claim in half the words and twice the force."],"focus":["concision","clarity"],"placeholder":"A morning check-in would cut disruptions and save teaching time."},
    {"id":"concise-edu-early-09","level":"early","profession":"education","title":"Sub plans that over-explain","scenario":"Your sub plans explain the reasoning behind every routine: why the pencil system exists, the history of the seating chart, your philosophy on bathroom passes. The sub needs instructions, not context — and it's now four pages.","task":"Rewrite one over-explained routine as a bare instruction.","tips":["The sub needs what to do, not why it evolved.","'One student out at a time; sign the clipboard' — done.","Save your philosophy for the handoff letter to next year's teacher."],"focus":["concision","precision"]},
    {"id":"concise-edu-early-10","level":"early","profession":"education","title":"The slide with too many words","scenario":"You're a corporate trainer and your busiest slide has 90 words in six bullets. You watch attendees read the slide instead of listening to you — then stop doing either.","task":"Rewrite the slide's content as headline plus three short bullets, and move the rest to your spoken notes.","tips":["The slide is a billboard, not the script — you are the script.","Each bullet: a claim in six words or fewer.","If they can get it all by reading, you're redundant in the room."],"focus":["concision","impact"],"placeholder":"Headline: Feedback works when it's specific. Bullet 1:"},
    {"id":"concise-edu-early-11","level":"early","profession":"education","title":"'Each and every first and foremost'","scenario":"Your open-house speech draft is padded with doubled phrases: 'each and every student,' 'first and foremost,' 'hopes and dreams,' 'any questions or concerns whatsoever.' Spoken aloud, it sounds like filler because it is.","task":"Rewrite two of the padded sentences with the redundant pairs cut.","tips":["One word of each pair is doing the work — keep that one.","'Every student' means each and every student.","Spoken concision reads as confidence; padding reads as nerves."],"focus":["concision","impact"]},
    {"id":"concise-edu-early-12","level":"early","profession":"education","title":"Five paragraphs for a yes","scenario":"A parent asked whether her son can bring cupcakes Friday for his birthday. Your draft reply is five paragraphs covering the allergy policy, the schedule, party history, and your appreciation for her asking. The answer is yes.","task":"Rewrite the reply at the length the question deserves.","tips":["Yes, plus the one constraint that matters (nut-free, after lunch).","The allergy policy exists in the handbook; link or skip it.","Match reply length to question weight — always."],"focus":["concision","audience"],"placeholder":"Yes, we'd love that! Just two things: nut-free, and"},
    {"id":"concise-edu-early-13","level":"early","profession":"education","title":"The 30-second staff update","scenario":"You have a two-minute slot at the staff meeting to report on the book fair, but the agenda is running long and the principal asks everyone to compress. Your notes are a page.","task":"Write the 30-second spoken version: outcome, one number, one ask.","tips":["Result first: the fair cleared $1,400 for the library.","One detail people will repeat; cut the rest.","The ask gets the last sentence, where it's remembered."],"focus":["concision","structure"],"placeholder":"Book fair wrap-up in 30 seconds: we cleared $1,400 for the library."},
    {"id":"concise-edu-early-14","level":"early","profession":"education","title":"The hedge-heavy grade explanation","scenario":"Your email explaining a C+ hedges everywhere: 'I feel like perhaps the essay may not have fully demonstrated what she's probably capable of, and I think the grade sort of reflects that somewhat.' The parent can't tell what you actually assess.","task":"Rewrite the explanation with the hedges cut and the judgment plain.","tips":["'I feel like perhaps maybe' — pick 'The essay didn't' and stand on it.","Keep one honest qualifier if it's true; cut the other five.","Hedged grades invite appeals; clear ones invite plans."],"focus":["concision","clarity"],"placeholder":"The C+ reflects two things: the essay is missing a thesis, and"},
    {"id":"concise-edu-early-15","level":"early","profession":"education","title":"The recap nobody asked for","scenario":"Replying in a long email thread with a parent, you begin by summarizing the entire previous exchange: 'To recap our conversation: on Monday you asked about... I responded that... you then noted...' The new information is two lines at the bottom.","task":"Rewrite the reply as just the new information.","tips":["The thread is the recap — it's attached to your reply.","Open with the update, not the archaeology.","One clause of orientation ('About the retake —') is all the context needed."],"focus":["concision","clarity"],"placeholder":"Update on the retake: Dev scored an 88, so"},
    {"id":"concise-edu-early-16","level":"early","profession":"education","title":"The field-trip reminder, halved","scenario":"Tomorrow's trip reminder runs 140 words, restating the destination's educational value and thanking parents twice. The operative facts: arrive by 7:45, pack a disposable lunch, wear the class T-shirt.","task":"Rewrite the reminder at half the length, facts first.","tips":["Three facts, three lines, then stop.","One thank-you maximum, at the end.","The value of the trip was the permission slip's job — this is logistics."],"focus":["concision","clarity"],"placeholder":"Trip reminder for tomorrow: arrive 7:45,"},
    {"id":"concise-edu-early-17","level":"early","profession":"education","title":"Throat-clearing in the IEP input","scenario":"Your written input for a student's IEP review opens: 'In my capacity as his general education teacher, I would like to take this opportunity to share some observations that I have had the chance to make over the course of this semester.' The team's packet is 40 pages; every wasted line loses a reader.","task":"Rewrite the opening so the first sentence is an observation.","tips":["Your role is in the document header — don't restate it.","Start with the most important thing you've observed.","In long packets, the writer who starts fast gets read."],"focus":["concision","impact"],"placeholder":"Diego participates fully in discussions but produces almost no written work —"},
    {"id":"concise-edu-early-18","level":"early","profession":"education","title":"The recommendation letter opening","scenario":"Your first recommendation letter for a former TA applying to a teaching program opens: 'It is with great pleasure and without any hesitation whatsoever that I write this letter in enthusiastic support of...' Forty words of ceremony before any evidence.","task":"Rewrite the opening sentence so it makes a specific claim about the candidate.","tips":["Ceremonial openings are invisible to admissions readers — claims aren't.","Lead with the strongest true statement you can evidence.","'The strongest TA I've worked with' beats 'great pleasure' every time."],"focus":["concision","impact"],"placeholder":"Priya is the most instinctive teacher I've seen at the start of a career —"},
    {"id":"concise-edu-early-19","level":"early","profession":"education","title":"The course description diet","scenario":"You're a corporate trainer and the catalog gives your course 60 words. Your draft is 200, full of phrases like 'participants will have the opportunity to engage with a variety of practical frameworks.' Enrollment depends on this blurb.","task":"Cut the description to 60 words that sell the outcome.","tips":["Lead with what attendees can do afterward.","'Opportunity to engage with' → 'learn' or 'practice.'","Every phrase must survive the question: does this help someone decide?"],"focus":["concision","impact"]},
    {"id":"concise-edu-early-20","level":"early","profession":"education","title":"Directions kids stop reading","scenario":"Your assignment sheet's directions run nine sentences. You watch students read two, then raise their hands to ask what to do. The assignment is simple: pick a biography, read it, present three facts.","task":"Rewrite the directions at the length a ten-year-old will finish.","tips":["Numbered steps, one clause each.","Cut the encouragement from the middle of the instructions — it interrupts.","If a step needs explaining, explain it out loud, not on the sheet."],"focus":["concision","audience"],"placeholder":"1. Pick a biography from the cart. 2."},
    {"id":"concise-edu-early-21","level":"early","profession":"education","title":"'Quick question' that isn't quick","scenario":"Your message to a colleague starts: 'Hey! Hope your week is going well! Quick question for you when you get a chance, no rush at all, whenever works...' The question finally appears in line six.","task":"Rewrite the message so the question appears in line one.","tips":["Warmth fits in two words; the question fits in one line.","'No rush' repeated three times means it will never happen.","Respecting their time is the friendliest thing in the message."],"focus":["concision","clarity"],"placeholder":"Hi! Do you have a copy of the unit 3 vocab quiz I could adapt?"},
    {"id":"concise-edu-early-22","level":"early","profession":"education","title":"The fundraiser pitch, tightened","scenario":"Your fundraiser paragraph for the school website runs 130 words before mentioning what the money buys or how to give. Donors decide in seconds.","task":"Rewrite it at half the length with the purpose and the action up front.","tips":["First line: what the money buys, concretely.","Second: how to give, in one step.","Gratitude closes; it doesn't open."],"focus":["concision","impact"],"placeholder":"We're raising $600 to put five new tablets in the reading corner."},
    {"id":"concise-edu-early-23","level":"early","profession":"education","title":"Facts only in the incident report","scenario":"Your incident report draft includes: 'I believe he was probably feeling frustrated, which is understandable given the morning he'd had, and I think that may be why the pushing occurred.' Interpretations are doing the work facts should do.","task":"Rewrite the passage as observable facts, cutting speculation.","tips":["Write what a camera would record: actions, words, times.","Your interpretation can be one labeled sentence at the end — or omitted.","Reports full of 'probably' don't protect you or the student."],"focus":["concision","precision"],"placeholder":"At 10:12, during the transition to math, Owen pushed"},
    {"id":"concise-edu-early-24","level":"early","profession":"education","title":"Thanks plus one more thing","scenario":"A parent volunteer ran your class party beautifully and you also need her to send back the reimbursement form by Friday. Your thank-you email is so long and grateful that the form request in the final line will vanish.","task":"Rewrite so the thanks is warm but brief and the action item is unmissable.","tips":["Two sentences of specific thanks beat eight of general praise.","Give the ask its own line, with the date.","Specific gratitude ('the craft table idea') lands harder than volume."],"focus":["concision","clarity"]},
    {"id":"concise-edu-early-25","level":"early","profession":"education","title":"The voicemail that fits","scenario":"You need to leave a parent a voicemail about scheduling a conference. Your last attempt rambled for 90 seconds and got cut off before the callback number. This time you're scripting it first.","task":"Write a voicemail script under 30 seconds: who, why, the ask, the number — twice.","tips":["Purpose in the first sentence; no 'so, anyway' spirals.","Say the callback number slowly, early, and again at the end.","Script the ending — voicemails die in the wind-down."],"focus":["concision","structure"],"placeholder":"Hi Ms. Rivera, this is Ms. Chen, Ava's teacher. I'd like to set up a"}
  ],
  "precision-and-evidence": [
    {"id":"precision-edu-early-01","level":"early","profession":"education","title":"'Doing much better' in math","scenario":"You're emailing a parent that her son is 'doing much better in math.' The actual evidence: his last three quiz scores were 62, 74, and 85, and he now finishes classwork without one-on-one help. 'Much better' could mean anything.","task":"Rewrite the sentence so the numbers carry the claim.","tips":["Three scores in a row tell the story better than any adverb.","Add one observable change from class — what he does now that he didn't.","Specific progress invites parents to keep it going; vague progress invites doubt."],"focus":["precision","impact"],"placeholder":"Marcus's last three quiz scores tell the story: 62, 74, and 85 —"},
    {"id":"precision-edu-early-02","level":"early","profession":"education","title":"The comment that fits every child","scenario":"Your report-card draft says a student is 'a pleasure to have in class and is making good progress.' It could describe any of your 26 students. What's true of her specifically: she asks the first question after every lesson, and her writing stamina grew from three sentences to a full page.","task":"Rewrite the comment with the two specifics.","tips":["If the comment fits every child, it describes none.","Name one behavior and one measurable change.","Parents keep report cards; give them a sentence worth keeping."],"focus":["precision","audience"],"placeholder":"Zoe asks the first question after nearly every lesson, and her writing has grown from"},
    {"id":"precision-edu-early-03","level":"early","profession":"education","title":"'Some supplies' gets no budget","scenario":"Your request to the office says the class needs 'some more art supplies for the spring unit.' The secretary can't order 'some.' You actually need 30 watercolor sets at $4 each and two rolls of butcher paper — $132 total, by April 7.","task":"Rewrite the request with items, quantities, cost, and date.","tips":["'Some' forces a follow-up email; a list gets ordered.","Total the cost yourself — don't make the approver do math.","The date needed is part of the request, not a footnote."],"focus":["precision","concision"],"placeholder":"Order request for the spring art unit: 30 watercolor sets ($4 each) and"},
    {"id":"precision-edu-early-04","level":"early","profession":"education","title":"'Disruptive all morning'","scenario":"Your behavior log entry reads 'Deon was disruptive all morning.' If this ever supports a support-plan meeting, 'disruptive' won't hold. What happened: he left his seat six times during the math block, called out over two classmates, and tore up his worksheet at 10:40.","task":"Rewrite the log entry as countable, observable behavior.","tips":["Write what a camera would record: actions, counts, times.","'Disruptive' is your conclusion; the log needs the evidence.","Precise logs protect the student and you."],"focus":["precision","clarity"],"placeholder":"During the 9:30-10:45 math block, Deon left his seat six times,"},
    {"id":"precision-edu-early-05","level":"early","profession":"education","title":"IEP input that holds up","scenario":"The special-education team asked for your classroom input on a student's attention. Your draft says he 'struggles to focus and is easily distracted.' The team writes goals from specifics: he sustains independent work for about four minutes before leaving task, and headphones during writing double that.","task":"Write 2 sentences of input with the durations and the condition that helps.","tips":["Time on task is measurable; 'struggles to focus' isn't.","Include what helps — that becomes the accommodation.","The team can only write goals as precise as your input."],"focus":["precision","impact"],"placeholder":"In independent work, Theo stays on task about four minutes before"},
    {"id":"precision-edu-early-06","level":"early","profession":"education","title":"The intervention update, quantified","scenario":"Your principal asked how the lunchtime math group is going. Your draft: 'The kids are making really great progress.' The data: five of seven students gained at least a level on the unit check, and the other two attend inconsistently.","task":"Write a 2-sentence update where the numbers make the case.","tips":["'Five of seven' is a result; 'great progress' is a mood.","Name the exception honestly — it makes the wins credible.","End with what you'll do about the two."],"focus":["precision","concision"],"placeholder":"Five of seven students in the lunch group gained at least a level on"},
    {"id":"precision-edu-early-07","level":"early","profession":"education","title":"'The workshop went really well'","scenario":"You're a new corporate trainer reporting on yesterday's session. Your draft says it 'went really well and people seemed engaged.' You have data: 27 of 30 completed the exercises, the feedback average was 4.4/5, and three people asked for a follow-up session.","task":"Rewrite the report so every claim carries evidence.","tips":["'Seemed engaged' is an impression; '27 of 30 completed' is a fact.","Requests for more are the strongest engagement data — use them.","Numbers let your manager forward the report upward unchanged."],"focus":["precision","impact"],"placeholder":"Yesterday's session: 27 of 30 completed all exercises, feedback averaged 4.4/5, and"},
    {"id":"precision-edu-early-08","level":"early","profession":"education","title":"'Working hard on fractions'","scenario":"Your newsletter says 'we've been working hard on fractions this month.' Parents can't see 'working hard.' What students can now do: compare fractions with unlike denominators and explain why 3/4 is bigger than 2/3.","task":"Rewrite the line so parents know what their child can now do.","tips":["Describe the new ability, not the effort.","A try-at-home example ('ask your child which is bigger...') makes it real.","'Can now do X' is the unit of progress parents understand."],"focus":["precision","audience"],"placeholder":"Your child can now compare fractions with different denominators — ask them"},
    {"id":"precision-edu-early-09","level":"early","profession":"education","title":"'Misses a lot of school'","scenario":"You're raising an attendance concern with the counselor. Your draft says a student 'misses a lot of school and it's hurting her.' The record: nine absences in six weeks, six of them Mondays, and she failed the two quizzes given on days after absences.","task":"Rewrite the concern with the pattern and the academic link.","tips":["Nine absences is a fact; 'a lot' is an argument waiting to happen.","The Monday pattern is the actionable detail — surface it.","Tie absences to a consequence you can document."],"focus":["precision","structure"],"placeholder":"Lily has nine absences in six weeks — six of them Mondays —"},
    {"id":"precision-edu-early-10","level":"early","profession":"education","title":"Where exactly they got lost","scenario":"You tell your grade team 'the kids are struggling with the new science unit.' The team can't fix 'struggling.' What you saw: 18 of 26 missed the question on variables, and most confusion traces to one worksheet's wording in lesson three.","task":"Restate the concern with the count and the location of the problem.","tips":["'18 of 26 missed the variables question' points to a fix; 'struggling' points nowhere.","Name the lesson and the material — precision makes it repairable.","Bring one student answer as the exhibit."],"focus":["precision","clarity"],"placeholder":"On the unit check, 18 of 26 missed the variables question, and I think it traces to"},
    {"id":"precision-edu-early-11","level":"early","profession":"education","title":"The trip budget, itemized","scenario":"Your field-trip proposal says the science center trip 'should be affordable for most families.' The office needs numbers: $11 admission, $6 bus share, lunch from home — $17 per student, and the class fund can cover any student who needs it.","task":"Write the cost section with the exact breakdown and the safety net.","tips":["'Affordable' is a judgment; $17 is information.","Itemizing shows there's nothing hidden.","Naming the hardship plan up front answers the question parents won't ask aloud."],"focus":["precision","audience"],"placeholder":"Cost per student is $17: $11 admission plus $6 bus share."},
    {"id":"precision-edu-early-12","level":"early","profession":"education","title":"'Fine' is not an answer","scenario":"At conferences, a parent asks how her daughter is doing and your instinct says 'really well overall.' You have five minutes and real evidence: reading a level above benchmark, strong in discussion, and multiplication facts are the one gap.","task":"Write the 3-sentence spoken answer anchored in the evidence.","tips":["One strength with proof, one gap with a plan — that's a conference.","'Above benchmark' means nothing until you translate it.","Parents remember specifics; they forget 'really well.'"],"focus":["precision","audience"],"placeholder":"Maya reads a level above benchmark, and she's one of my strongest discussion voices."},
    {"id":"precision-edu-early-13","level":"early","profession":"education","title":"'Always broken' won't get fixed","scenario":"Your email to IT says the class Chromebooks are 'always broken and it's disrupting lessons.' The countable truth: 6 of 30 won't hold a charge past 20 minutes, and cart slots 4, 11, and 19 don't charge at all.","task":"Rewrite the request with the counts and slot numbers.","tips":["'Always' invites a debate; '6 of 30' invites a work order.","Slot numbers turn an inspection visit into a repair visit.","Say what you need: six working replacements or fixed slots."],"focus":["precision","clarity"],"placeholder":"Six of our 30 Chromebooks won't hold a charge past 20 minutes, and cart slots 4, 11, and 19"},
    {"id":"precision-edu-early-14","level":"early","profession":"education","title":"The tardy pattern","scenario":"You're emailing a parent about lateness. Your draft says her son is 'often late, which affects his learning.' The record: 12 tardies in four weeks, all during first-period reading, and he's missed the mini-lesson each time — the part where the day's skill gets taught.","task":"Rewrite with the count and the specific cost of the missed minutes.","tips":["12 in four weeks is a pattern no one can wave off.","Say exactly what he misses — 'the part where the skill is taught.'","Precision here is advocacy, not accusation."],"focus":["precision","impact"],"placeholder":"Nate has been late 12 times in the past four weeks, and each time he misses"},
    {"id":"precision-edu-early-15","level":"early","profession":"education","title":"Defending the grade with the rubric","scenario":"A parent emails that her daughter's essay grade 'seems subjective.' Your reply draft says you 'grade everyone fairly using consistent standards.' What you have: a rubric with four scored dimensions, her daughter's 2/4 on evidence, and two model sentences showing what a 4 looks like.","task":"Write the reply that answers with the rubric, not a defense of your fairness.","tips":["Show the dimension and the score, not your character.","One concrete example of what a 4 looks like ends most disputes.","Offer the path up: revise-and-resubmit or a conference."],"focus":["precision","structure"],"placeholder":"Fair question — let me show you exactly where the points went. The rubric scores four areas, and"},
    {"id":"precision-edu-early-16","level":"early","profession":"education","title":"Participation, counted","scenario":"You want to tell a shy student's parents she's 'really coming out of her shell.' The evidence you actually tallied: she volunteered answers four times this week — up from zero in September — and led her lab group's report on Friday.","task":"Write the 2-sentence note with the tally doing the work.","tips":["'Four times, up from zero' is a story in five words.","Name the biggest single moment — leading the report.","Counting small behaviors is how you prove quiet growth."],"focus":["precision","impact"],"placeholder":"I counted this week: Priya volunteered answers four times — in September it was zero."},
    {"id":"precision-edu-early-17","level":"early","profession":"education","title":"The skeptical parent and the record","scenario":"A parent insists his son 'always does his homework' and the missing-work notices must be a mistake. Feelings won't settle this; the record will: 7 of the last 15 assignments were never submitted, and you have the dated log.","task":"Write a reply that presents the record without scoring points.","tips":["Dates and counts, delivered flatly, need no adjectives.","Offer to walk through the log together — transparency beats assertion.","Leave him a face-saving path: a system to track it going forward."],"focus":["precision","audience"],"placeholder":"Here's the record so we're looking at the same thing: 7 of the last 15 assignments"},
    {"id":"precision-edu-early-18","level":"early","profession":"education","title":"'People loved it' won't renew the contract","scenario":"You're a corporate trainer and the client asks whether the pilot program is worth renewing. Your instinct: 'the team really loved it.' The evidence: 92% completion, quiz scores up 18 points pre-to-post, and two managers requested seats for their teams.","task":"Write the 2-3 sentence renewal case built on the three data points.","tips":["'Loved it' is a review; 'scores up 18 points' is a business case.","Unprompted requests for more seats are gold — lead with or end on them.","Let the client conclude 'worth it' from the numbers."],"focus":["precision","impact"],"placeholder":"Three numbers from the pilot: 92% completion, quiz scores up 18 points, and"},
    {"id":"precision-edu-early-19","level":"early","profession":"education","title":"The bake sale, by the numbers","scenario":"Your thank-you note to families says the bake sale 'was a huge success thanks to everyone's generosity.' The actual results: $487 raised toward the $600 field-trip goal, 14 family volunteers, sold out by 1pm.","task":"Rewrite the note so families see exactly what they accomplished.","tips":["$487 toward $600 tells families what's done and what's left.","'Sold out by 1pm' is more vivid than 'huge success.'","Specific results make the next ask easier."],"focus":["precision","impact"],"placeholder":"You raised $487 of our $600 field-trip goal — and we sold out by 1pm."},
    {"id":"precision-edu-early-20","level":"early","profession":"education","title":"What 'below grade level' looks like","scenario":"You have to tell parents their son reads below grade level. The phrase alone either terrifies or bounces off. The precise picture: he reads grade-level words accurately but at 40 words per minute — half the benchmark — so he loses the meaning by the end of a sentence.","task":"Write 2-3 sentences that replace the label with the specific picture.","tips":["Describe the mechanism: accurate but slow, so comprehension pays the price.","One number (40 vs 80) anchors the whole conversation.","End with the matching fix — fluency practice, not harder books."],"focus":["precision","audience"],"placeholder":"Ben reads the words accurately — the issue is speed. He's at about 40 words a minute"},
    {"id":"precision-edu-early-21","level":"early","profession":"education","title":"The reference letter of adjectives","scenario":"You're writing a reference for your classroom aide who's applying to a teaching program. Your draft calls her 'dedicated, reliable, and wonderful with children.' What you've watched her do: de-escalate a meltdown in two minutes, run guided reading for four kids daily, and redesign the check-in chart the whole grade now uses.","task":"Rewrite one paragraph so the evidence replaces the adjectives.","tips":["Every adjective should be convertible to a scene — convert them.","'The whole grade adopted her chart' is third-party proof.","Specific letters get read; generic ones get skimmed."],"focus":["precision","impact"],"placeholder":"In March I watched Dana calm a student mid-meltdown in under two minutes —"},
    {"id":"precision-edu-early-22","level":"early","profession":"education","title":"'More books' is not a proposal","scenario":"Your classroom library request says you need 'more books at more levels.' The budget meeting is Thursday. The real gap: you have four books below level J for the six students who read there, and 25 titles at $6 each — $150 — closes it.","task":"Rewrite the request with the gap, the count, and the cost.","tips":["Name the gap as students affected, not shelf aesthetics.","A dollar figure with a per-unit breakdown reads as done homework.","Requests with numbers survive budget meetings you're not in."],"focus":["precision","concision"],"placeholder":"Six of my students read below level J, and I own four books they can read."},
    {"id":"precision-edu-early-23","level":"early","profession":"education","title":"One insight from the spreadsheet","scenario":"At the data meeting you have 90 seconds to present your class's assessment results. The spreadsheet has 26 rows and 12 columns. The insight hiding in it: every student who missed the inference questions also scored low on vocabulary — the gap is word knowledge, not reading skill.","task":"Write the 2-sentence spoken takeaway that gives the room the insight, not the spreadsheet.","tips":["Lead with the pattern, not the columns.","Name the implication: what should change on Monday.","Data presentations are judged by the sentence people repeat after."],"focus":["precision","concision"],"placeholder":"One pattern jumped out: every student who missed inference also scored low on vocabulary."},
    {"id":"precision-edu-early-24","level":"early","profession":"education","title":"'Recess is getting rough'","scenario":"You want the principal to add supervision to the east playground. Your draft says recess 'is getting rough out there.' Your duty log: five physical incidents in two weeks, four near the climbing structure, all in the last ten minutes of the period.","task":"Rewrite the request with the counts, the location, and the time window.","tips":["Five incidents, one location, one time window — that's a staffing answer.","Vague alarm gets sympathy; patterns get schedule changes.","Propose the fix your data implies: one adult by the structure after 12:20."],"focus":["precision","structure"],"placeholder":"My duty log shows five physical incidents in two weeks — four by the climbing structure,"},
    {"id":"precision-edu-early-25","level":"early","profession":"education","title":"'Huge improvement,' calibrated","scenario":"You're about to tell a parent his daughter has made 'huge improvement' in writing. True, but overselling sets up next quarter's disappointment. The calibrated truth: paragraphs went from two sentences to six with a clear topic sentence, spelling is unchanged, and the next target is editing her own work.","task":"Write the 3-sentence spoken update: gain, unchanged area, next step.","tips":["Calibrate: name what grew AND what didn't move yet.","Numbers make praise trustworthy — two sentences to six.","'Next we're working on' turns a report into a plan."],"focus":["precision","clarity"],"placeholder":"Real growth this quarter: Ana's paragraphs went from two sentences to six, with clear topic sentences."}
  ],
  "executive-presence": [
    {"id":"presence-edu-early-01","level":"early","profession":"education","title":"Recommend, don't survey","scenario":"Your grade team asked you to compare three phonics programs and report back. You did the work: one clearly fits your students. Your slide draft lists pros and cons of all three and ends with 'thoughts?' — handing the decision back to a room with less information than you.","task":"Write the 2-3 sentence spoken recommendation that names your pick and the deciding reason.","tips":["'I recommend X because...' — the pros/cons table is backup, not the message.","You did the research; the point of view is the deliverable.","Name the runner-up and when it would win instead."],"focus":["impact","clarity"],"placeholder":"After comparing all three, I recommend Fundations — it's the only one with"},
    {"id":"presence-edu-early-02","level":"early","profession":"education","title":"Cut the 'sort of maybe'","scenario":"In conferences you hear yourself saying 'I sort of think she might benefit from maybe reading a bit more at home?' You DO think that — the data says it plainly. The hedges are making a clear professional judgment sound like a guess.","task":"Rewrite the sentence as calm, unhedged professional advice.","tips":["One clean sentence: 'Fifteen minutes of reading at home would make a real difference.'","Hedge the genuinely uncertain; state the well-supported.","Parents came for your judgment — give it."],"focus":["clarity","impact"],"placeholder":"My recommendation is fifteen minutes of reading at home, five nights a week."},
    {"id":"presence-edu-early-03","level":"early","profession":"education","title":"Three points, announced","scenario":"You have two minutes at the staff meeting to report on the attendance-committee work. Last time you wandered and the takeaway got lost. This time you'll signpost: tell them there are three things, then number them as you go.","task":"Write the opening sentence plus the three signposted points.","tips":["'Three things: the data, what we tried, what we need' — then deliver exactly that.","Numbering keeps the room with you and keeps you honest.","The third point should be the ask, so the segment ends on action."],"focus":["structure","clarity"],"placeholder":"Three things on attendance: what the data shows, what we piloted, and one thing we need from you."},
    {"id":"presence-edu-early-04","level":"early","profession":"education","title":"Expectations without pleading","scenario":"It's your first September and your classroom-rules speech drafts as 'I really hope we can all try to be respectful, okay?' Hope is not a management plan. The same content, delivered as settled fact, is what makes week one calm.","task":"Write the 3-4 spoken sentences that state how the room works — decided, warm, no 'okay?'","tips":["State it as how things ARE here, not how you wish they'd be.","Drop every 'try to,' 'hopefully,' and trailing 'okay?'","Warmth and authority stack fine; pleading undercuts both."],"focus":["clarity","impact"]},
    {"id":"presence-edu-early-05","level":"early","profession":"education","title":"'I just thought maybe'","scenario":"Your email to the principal opens: 'Sorry to bother you — I just thought maybe it might be worth possibly looking at the dismissal procedure?' You've watched the bottleneck daily for a month and have a concrete fix. The message deserves the confidence your observation earned.","task":"Rewrite the opening as a direct, professional proposal.","tips":["Delete 'just,' 'maybe,' 'possibly,' and the apology — read what's left.","Replace 'might be worth looking at' with what you observed and propose.","Directness in writing reads as competence, not rudeness."],"focus":["clarity","concision"],"placeholder":"I've watched the dismissal bottleneck daily for a month and want to propose a fix:"},
    {"id":"presence-edu-early-06","level":"early","profession":"education","title":"'What do you think we should do?'","scenario":"The principal asks your grade team what to do about the struggling homework-club pilot, then looks at you: 'You run it — what do you think?' Your instinct is to list options and let her choose. She asked what YOU think.","task":"Write the 2-3 sentence spoken answer that takes a position.","tips":["Lead with the verdict: keep it, kill it, or change it.","One reason, grounded in what you've seen running it.","Options-without-opinion wastes the closest view in the room: yours."],"focus":["clarity","impact"],"placeholder":"I'd change the format rather than cancel it — attendance is the problem, not the help."},
    {"id":"presence-edu-early-07","level":"early","profession":"education","title":"Younger than everyone in the room","scenario":"You're a 24-year-old trainer opening a session for managers twice your age. Your drafted opening apologizes: 'I know many of you have way more experience than me...' Naming your inexperience first hands the room a reason to check out.","task":"Write an opening (2-3 sentences) that earns the room through preparation, not apology.","tips":["Open with what they'll leave with, stated with certainty.","Your credential is the material and the prep — let it show, don't plead it.","Never volunteer a discount on yourself."],"focus":["impact","audience"],"placeholder":"By the end of this session, you'll have a script for the feedback conversation most managers avoid."},
    {"id":"presence-edu-early-08","level":"early","profession":"education","title":"The gradebook error, owned","scenario":"You entered a whole quiz column wrong and three parents saw incorrect grades online before you caught it. Your correction email drafts as five sentences of apology spiral. Presence here is owning it in one clean line and moving to the fix.","task":"Write the 3-sentence email: what happened, it's fixed, what you changed.","tips":["One sentence of ownership, no groveling — then the correction.","State the safeguard so the apology carries information.","Steadiness under your own mistake is what builds trust."],"focus":["clarity","structure"],"placeholder":"I entered last week's quiz scores incorrectly — the online grades were wrong from Monday to Wednesday. They're corrected now."},
    {"id":"presence-edu-early-09","level":"early","profession":"education","title":"Holding the seating change","scenario":"You moved a student's seat for good reasons — he and his tablemate derailed each other daily. His mother emails asking you to move him back because he's 'upset.' You considered it; the answer is no, with a review date.","task":"Write the reply that holds the decision kindly and firmly.","tips":["Acknowledge the feeling; keep the decision — those are separate.","Give the reason once, cleanly; don't relitigate it per email.","A review date ('let's check in after two weeks') shows the decision has a brain, not an ego."],"focus":["clarity","audience"],"placeholder":"I understand the move was upsetting, and I'm keeping it in place — here's why."},
    {"id":"presence-edu-early-10","level":"early","profession":"education","title":"'I'm just the TA'","scenario":"In the student-support meeting you preface your observation with 'I'm just the TA, so I might be wrong, but...' You spend more one-on-one minutes with this student than anyone at the table. Your data is not junior even if your title is.","task":"Rewrite the contribution without the self-discount.","tips":["Replace 'I'm just the TA' with your actual authority: 'I work with him one-on-one daily.'","Report the observation plainly; let its specificity carry the weight.","The table needs your data, not your disclaimer."],"focus":["impact","precision"],"placeholder":"I work with Andre one-on-one every day, and here's what I see:"},
    {"id":"presence-edu-early-11","level":"early","profession":"education","title":"The data has a conclusion — say it","scenario":"You're presenting benchmark results at the team meeting. Your slides show the numbers and end there, letting the room decide what they mean. You already know what they mean: the current spelling block isn't working and two groups need regrouping.","task":"Write the closing 2 sentences that move from data to your recommendation.","tips":["'The data says X, so I recommend Y' — the second half is the job.","Reporting without recommending asks the room to redo your thinking.","Invite challenge to the recommendation, not to whether you should make one."],"focus":["impact","structure"],"placeholder":"Here's what I take from this: the spelling block isn't moving the bottom two groups."},
    {"id":"presence-edu-early-12","level":"early","profession":"education","title":"The conference with a spine","scenario":"Your parent conferences drift — ten minutes vanish into anecdotes and the growth area never gets airtime. The fix is structure said aloud at the start: strengths, one growth area, the plan, then questions.","task":"Write the conference-opening sentence that lays out the map, plus the transition line into the growth area.","tips":["A spoken agenda is presence: it says you've decided how this goes.","'The second thing — one area we're working on' makes hard topics arrive on schedule.","Parents relax when they can see the whole shape of the meeting."],"focus":["structure","audience"],"placeholder":"I want to cover three things in our ten minutes: what's going well, one thing we're working on, and"},
    {"id":"presence-edu-early-13","level":"early","profession":"education","title":"Back-to-school night, decided","scenario":"You have five minutes in front of thirty parents at back-to-school night — your first. Your draft hedges everything: 'we'll kind of see how the year goes,' 'I'm still figuring out my homework approach.' Parents came to learn whether their child's teacher has a plan.","task":"Write the 3-sentence version of your homework-and-communication policy, stated like a plan.","tips":["'Homework is 20 minutes, four nights; I answer email within a day' — decided beats perfect.","You can change a policy later; you can't re-run a first impression.","Certainty about structure leaves room for warmth everywhere else."],"focus":["clarity","audience"],"placeholder":"Homework is twenty minutes a night, Monday through Thursday — reading plus one short practice page."},
    {"id":"presence-edu-early-14","level":"early","profession":"education","title":"Weather call, made aloud","scenario":"Rain is forecast for tomorrow's outdoor field day and co-teachers keep asking what you want to do — it's your event. You've checked the radar and the gym availability. Deferring with 'whatever people think' leaves thirty families in limbo overnight.","task":"Write the 2-sentence message to staff announcing your call and the reason.","tips":["Make the call, state the trigger you used, move to logistics.","A decision announced tonight beats a perfect one at 6am.","'If conditions change, here's the fallback' covers you without wobbling."],"focus":["clarity","impact"],"placeholder":"We're moving field day to the gym — radar shows rain through 1pm. Here's the revised schedule:"},
    {"id":"presence-edu-early-15","level":"early","profession":"education","title":"The veteran raises an eyebrow","scenario":"A 20-year veteran teacher watches your station-rotation lesson and asks, in the hallway, 'You really think that's the best use of instructional time?' The question is a test of whether you know why you do what you do. You do.","task":"Write the 2-3 sentence spoken answer that explains your reasoning without apologizing for it.","tips":["Answer the question asked: yes, and here's the reasoning and the early results.","Cite what you're watching for — that shows judgment, not stubbornness.","Respect her experience by engaging the substance, not by folding."],"focus":["clarity","impact"]},
    {"id":"presence-edu-early-16","level":"early","profession":"education","title":"Directing the parent volunteers","scenario":"Three parent volunteers arrive for the class party and you catch yourself over-apologizing: 'Sorry, would you maybe mind possibly setting up the craft table?' They came to be directed. Clear assignments are a courtesy, not bossiness.","task":"Write the 3-sentence welcome that assigns each station clearly and warmly.","tips":["Name, station, one key detail — for each volunteer.","'Thank you' once, then instructions; not instructions wrapped in apology.","People relax when someone is clearly running the room."],"focus":["clarity","structure"],"placeholder":"Thank you all for coming — here's the plan. Maria, you have the craft table:"},
    {"id":"presence-edu-early-17","level":"early","profession":"education","title":"'This is stupid — why do we have to?'","scenario":"Mid-lesson, a student announces the assignment is stupid and asks why they have to do it. The class watches how you respond. Arguing loses; ignoring loses; a calm one-line answer and a return to work wins.","task":"Write the calm 1-2 sentence spoken response that answers and moves on.","tips":["Give the real reason in one sentence — kids can smell a dodge.","No sarcasm, no debate invitation; end by redirecting to the task.","Your tone is the lesson the other 25 students are learning."],"focus":["clarity","impact"]},
    {"id":"presence-edu-early-18","level":"early","profession":"education","title":"Newest voice at the table","scenario":"Your PLC is choosing next unit's writing assessment and the discussion is circling. You piloted exactly this prompt during student teaching and know its failure mode. You've been quiet for twenty minutes because everyone else has more tenure.","task":"Write the 2-3 sentence spoken contribution that offers your evidence without a preamble of apology.","tips":["Skip 'this might be dumb but' — go straight to 'I've run this prompt; here's what happened.'","Direct experience outranks tenure on this specific question.","End with a concrete suggestion, not just a warning."],"focus":["impact","precision"],"placeholder":"I've actually run this exact prompt — the timed version collapses for anyone below grade level in typing."},
    {"id":"presence-edu-early-19","level":"early","profession":"education","title":"Position first, deference second","scenario":"The district literacy specialist asked teachers to weigh in on moving your school to whole-class novels. You disagree, based on your class's reading spread. Your draft buries your position under three paragraphs of 'I could be wrong' and 'you know far better than I.'","task":"Rewrite the reply to state your position and evidence in the first two sentences.","tips":["Respectful and direct: 'I'd advise against it for our building — here's what my class data shows.'","One strong piece of evidence beats three hedged paragraphs.","Deference to expertise means engaging it, not pre-surrendering."],"focus":["clarity","structure"],"placeholder":"I'd advise against whole-class novels for our building. My class spans six reading levels, and"},
    {"id":"presence-edu-early-20","level":"early","profession":"education","title":"Taking the room back","scenario":"Ten minutes into your workshop, a senior manager starts answering every question and mini-lecturing the group. The room's attention is drifting to him. You need it back — without embarrassing your most senior attendee.","task":"Write the 1-2 sentence spoken redirect that reclaims the room and keeps his goodwill.","tips":["Name his contribution, park it, redirect: 'Great case — hold it for the debrief. Right now I want this side of the room.'","Move physically and vocally as you say it — presence is posture too.","Control of airtime is the trainer's job; the room is grateful when you do it."],"focus":["impact","audience"]},
    {"id":"presence-edu-early-21","level":"early","profession":"education","title":"From suggestion box to recommendation","scenario":"Your message to the team about arrival chaos reads: 'We could maybe try some kind of soft-start routine, possibly?' You've read the research, visited a classroom that uses them, and believe this is the answer. The wording is a suggestion box; the situation needs a recommendation.","task":"Rewrite it as a recommendation with a proposed first step.","tips":["'I recommend we pilot soft starts in our three rooms for two weeks' — verb, plan, timebox.","A pilot proposal lowers the stakes without lowering the confidence.","Ownership means you'll organize it — and saying so."],"focus":["clarity","impact"],"placeholder":"I recommend we pilot a soft-start routine in our three rooms for two weeks, starting Monday."},
    {"id":"presence-edu-early-22","level":"early","profession":"education","title":"The classroom voice at the IEP table","scenario":"At the IEP meeting, specialists trade acronyms and you feel your classroom observations shrinking in your throat. But you're the only person at the table who sees this student six hours a day. The meeting is incomplete without your view, stated plainly.","task":"Write the 2-3 sentence spoken contribution that states what you see and what you think the plan needs.","tips":["Your standing is the six hours a day — invoke it once, then report.","Plain classroom language is a contribution, not a deficiency, at an acronym-heavy table.","End with what you believe the plan needs from your seat."],"focus":["impact","clarity"],"placeholder":"From six hours a day with him: the plan needs a movement break before writing, not after."},
    {"id":"presence-edu-early-23","level":"early","profession":"education","title":"The ask, framed as a plan","scenario":"You want 30 minutes of aide time daily for your reading groups. Your draft to the principal reads like a plea: 'if there's any way, I know everyone's stretched...' Pleas get sympathy. Proposals — need, evidence, cost, plan — get resources.","task":"Rewrite the ask as a 3-sentence proposal.","tips":["Structure: what you need, what it produces, exactly when.","'30 minutes, 9:00-9:30, groups three and four' shows you've done the thinking.","Pre-empting the logistics objection is what makes yes easy."],"focus":["structure","impact"],"placeholder":"Proposal: 30 minutes of aide support daily, 9:00-9:30, so groups three and four get"},
    {"id":"presence-edu-early-24","level":"early","profession":"education","title":"Disagreeing with the room","scenario":"The staff meeting is converging on cutting morning recess to add intervention time. You think it will backfire — your hardest teaching hours are the ones after kids sit too long. Nodding along now means co-owning a decision you believe is wrong.","task":"Write the 2-3 sentence spoken dissent: respectful, specific, with an alternative.","tips":["Disagree with the plan, not the people: 'I want to push on this before we decide.'","Ground it in what you observe daily, not in vibes.","Offering an alternative converts dissent into contribution."],"focus":["clarity","impact"]},
    {"id":"presence-edu-early-25","level":"early","profession":"education","title":"'Are you new?' at the door","scenario":"A parent at open house looks at you and asks, 'Are you new? How long have you been teaching?' It's your first year. The honest answer can be delivered as a discount or as a fact followed by what you bring. Same facts, different presence.","task":"Write the 2-sentence spoken answer that tells the truth with a steady spine.","tips":["'This is my first year here' — then immediately what you're bringing: training, energy, a plan.","Don't inflate and don't cringe; both read instantly.","Confidence about your plan answers the question under the question."],"focus":["audience","impact"],"placeholder":"It's my first year — you're getting someone trained in the newest reading research and"}
  ],
  "answering-under-pressure": [
    {"id":"pressure-edu-early-01","level":"early","profession":"education","title":"'Is my kid behind?'","scenario":"Two minutes into the conference, a father asks flatly: 'Is she behind?' Your instinct is a five-minute tour of strengths before touching the question. He'll hear evasion. The answer is yes, in math, by about half a year — with a plan attached.","task":"Write the spoken answer that answers first, then frames.","tips":["First word answers: 'Yes, in math — and here's exactly where and what we're doing.'","Precision immediately after honesty is what keeps trust.","The plan is the comfort; don't substitute vagueness for it."],"focus":["clarity","audience"],"placeholder":"Yes — in math she's about half a year behind, specifically in fractions."},
    {"id":"pressure-edu-early-02","level":"early","profession":"education","title":"The doorway question","scenario":"Your principal appears in your doorway at 3:05: 'How's the new curriculum going?' You have 30 seconds of her attention, not ten minutes. A rambling answer teaches her not to ask you things.","task":"Write the 2-sentence answer: verdict first, one specific, one flag.","tips":["Verdict in five words: 'Good, with one gap.'","One concrete example proves you're actually tracking it.","Flag the problem now — doorway questions are how problems get resourced."],"focus":["concision","clarity"],"placeholder":"Honestly, good — the pacing works and the kids like the routines. One gap:"},
    {"id":"pressure-edu-early-03","level":"early","profession":"education","title":"'Why did she get a B?'","scenario":"A parent opens the phone call with 'Why did she get a B when she got As all last year?' The defensive answer explains your grading philosophy. The actual answer is specific: two missing labs and a test she can retake.","task":"Write the spoken answer that answers the actual question in the first sentence.","tips":["The question is 'why' — give the two reasons, then stop.","Last year's As are not your ledger; don't get pulled into comparing teachers.","End with the path: the retake window and the makeup labs."],"focus":["clarity","precision"],"placeholder":"Two things made it a B: two missing labs and the unit test."},
    {"id":"pressure-edu-early-04","level":"early","profession":"education","title":"The policy question you can't answer","scenario":"At curriculum night a parent asks whether the district will offer the gifted program next year. You genuinely don't know — it's above your pay grade and undecided. Guessing is how rumors start with you as the source.","task":"Write the 2-sentence answer: clean 'I don't know,' plus how you'll get them the answer.","tips":["'I don't know' delivered plainly builds more trust than a hedge.","Commit to the follow-up: who you'll ask and by when.","Never guess on district decisions — your guess becomes a quote."],"focus":["clarity","audience"],"placeholder":"I honestly don't know — that decision hasn't been made yet. Let me ask"},
    {"id":"pressure-edu-early-05","level":"early","profession":"education","title":"The email that says you're unfair","scenario":"A parent emails: 'You clearly have a problem with my son. He says you always single him out.' Your pulse spikes. The defensive reply and the capitulating reply are both wrong; the steady one addresses the concern with facts and an invitation.","task":"Write the 3-sentence reply: acknowledge, state facts calmly, propose the meeting.","tips":["Respond to the concern, not the accusation's temperature.","One or two verifiable facts — dates, incidents, what preceded them.","Move it to a meeting; hard conversations shrink in person and grow in email."],"focus":["audience","structure"],"placeholder":"I can hear how upset you are, and I want to sort this out directly. Here's what happened this week from my side:"},
    {"id":"pressure-edu-early-06","level":"early","profession":"education","title":"'When will we ever use this?'","scenario":"Mid-lesson on percentages, a student asks the eternal question: 'When will we ever use this?' Twenty-five kids wait to see if the answer is real. You have ten seconds for an honest, concrete answer — not a lecture on the value of mathematics.","task":"Write the 1-2 sentence spoken answer with one example from their actual lives.","tips":["Concrete beats noble: sales tax, phone battery, game stats.","Ten seconds, then back to the lesson — the answer is a footnote, not a detour.","An honest 'and some of it is training your brain to think in steps' can land too."],"focus":["audience","concision"]},
    {"id":"pressure-edu-early-07","level":"early","profession":"education","title":"The interview curveball","scenario":"In your teaching interview, the panel asks: 'Tell us about a lesson that failed.' The trap runs both ways — claiming none is a red flag, and spiraling into self-criticism is worse. The strong answer is a real failure plus what it changed in your practice.","task":"Write the 3-4 sentence spoken answer: the failure, the diagnosis, the change.","tips":["Pick a real, specific failure — panels can smell a fake one.","Spend one sentence on the failure and two on what you learned.","End in the present: what you now do differently every time."],"focus":["structure","impact"],"placeholder":"My third week of student teaching, I planned a debate for a class that didn't have the norms for it yet."},
    {"id":"pressure-edu-early-08","level":"early","profession":"education","title":"The homework question at PTA night","scenario":"At the PTA meeting a parent stands up: 'Why is there so much homework? Research says it doesn't even help at this age.' Thirty parents turn to you. She's partly right about the research, and your policy has a reason. Both things fit in a calm answer.","task":"Write the 3-sentence spoken answer that concedes what's true and explains your line.","tips":["Concede the true part first — it disarms the room.","Then your policy and its boundary: 20 minutes, reading-heavy, no penalties for a hard night.","Offer the follow-up conversation; don't litigate research at a mic."],"focus":["audience","clarity"],"placeholder":"You're right that the research on homework at this age is mixed — that's exactly why mine is capped at twenty minutes."},
    {"id":"pressure-edu-early-09","level":"early","profession":"education","title":"'Your numbers are wrong'","scenario":"Mid-presentation, an attendee interrupts: 'That retention statistic is outdated — we ran our own numbers.' You're a new trainer and the room is watching. If he's right, the worst move is defending the slide; if he's wrong, the worst move is folding.","task":"Write the 2-sentence spoken response that handles it without defensiveness either way.","tips":["'Tell me what you found' — engaging the data is strength, not weakness.","Commit to reconciling the sources after, and actually do it.","The room is scoring your composure, not your slide."],"focus":["impact","audience"]},
    {"id":"pressure-edu-early-10","level":"early","profession":"education","title":"Cold-called at the staff meeting","scenario":"The principal turns to you mid-meeting: 'You've been running the morning intervention — is it working?' You have partial data: attendance is strong, one measure improved, it's too early on the rest. You have 30 seconds to be honest and structured at the same time.","task":"Write the spoken answer: what you know, what you don't yet, when you will.","tips":["Answer the question's shape: 'Early signs yes; full answer in three weeks.'","Give the one solid data point you have.","Naming when you'll know more turns 'incomplete' into 'on schedule.'"],"focus":["structure","clarity"],"placeholder":"Early signs point to yes — attendance is at 90% and letter-sound scores are up."},
    {"id":"pressure-edu-early-11","level":"early","profession":"education","title":"The question with a question inside","scenario":"A parent asks: 'Do you think holding kids back ever works?' You know her son is on the retention-discussion list; the general question is really a specific one. Answering the abstract question ignores what she's actually asking; guessing at the specific one oversteps.","task":"Write the spoken answer that names the real question and answers what's yours to answer.","tips":["Surface it gently: 'Are you asking about Tomas? Let's talk about him directly.'","Answer the general honestly and briefly — the research is genuinely mixed.","The specific answer belongs in a scheduled meeting with the data in front of you."],"focus":["audience","clarity"]},
    {"id":"pressure-edu-early-12","level":"early","profession":"education","title":"'What are you doing about the bullying?'","scenario":"A parent calls, upset: 'My daughter says kids are mean to her at lunch and nothing happens. What are you actually doing?' You do have actions underway — seat changes, a counselor referral, closer supervision — but some details involve other children and aren't shareable.","task":"Write the spoken answer that gives real actions without breaching other students' privacy.","tips":["Name your concrete actions and the timeline — 'watching' isn't one.","State the boundary plainly: what involves other kids stays private, in both directions.","Give her a specific check-in date so 'nothing happens' can't be the story."],"focus":["clarity","audience"],"placeholder":"Here's what's already happening: I changed the lunch seating Monday, and"},
    {"id":"pressure-edu-early-13","level":"early","profession":"education","title":"The accommodation you missed","scenario":"In the IEP meeting, the family's advocate asks pointedly: 'His plan requires preferential seating — why was he in the back row in October?' It's true; you missed it in the seating shuffle. Eight people wait for your answer, and excuses will make it worse.","task":"Write the spoken answer: own it, state the fix, state the safeguard.","tips":["'You're right, and here's what happened' — one sentence, no squirm.","The fix and the safeguard are the real answer to the question.","Owning a miss cleanly, on the record, is what credibility looks like."],"focus":["clarity","impact"],"placeholder":"You're right — during the October seating change I missed it, and that's on me."},
    {"id":"pressure-edu-early-14","level":"early","profession":"education","title":"'Why did you choose that activity?'","scenario":"In your post-observation debrief, the principal asks why you chose stations over direct instruction for the fractions lesson. It's a genuine question, but under evaluation pressure it feels like an attack. It isn't — and a reasoned answer is what she's listening for.","task":"Write the 2-3 sentence spoken answer: the pedagogical reason plus how you checked it worked.","tips":["Answer as a designer: what the choice bought your students that day.","Cite your check for understanding — decisions plus evidence is the pro move.","Confidence about reasoning can coexist with openness to notes."],"focus":["clarity","structure"],"placeholder":"I chose stations because this group needs to handle fractions physically before"},
    {"id":"pressure-edu-early-15","level":"early","profession":"education","title":"'How old ARE you?'","scenario":"At pickup, a parent squints at you: 'You look so young — have you done this before?' Beneath the rudeness is a real question: is my child in good hands? Answer that question, not the insult.","task":"Write the 1-2 sentence spoken reply, warm and unrattled.","tips":["Skip defending your age; answer the trust question underneath.","One line of substance: your training, your plan, how their kid is doing.","Humor helps if it's yours; composure is mandatory either way."],"focus":["audience","impact"]},
    {"id":"pressure-edu-early-16","level":"early","profession":"education","title":"Two questions in one breath","scenario":"A parent at conferences fires a double-barrel: 'Why is he bored in class, and are you going to test him for gifted?' Answering them tangled together satisfies neither. The move: split them out loud, then answer each on its own terms.","task":"Write the spoken response that separates and answers both.","tips":["Name the split: 'Two different questions — let me take them one at a time.'","Answer the easier one crisply, then give the harder one real airtime.","Separating questions is a calm move that lowers the temperature."],"focus":["structure","clarity"],"placeholder":"Those are two separate questions, so let me take them one at a time. On boredom:"},
    {"id":"pressure-edu-early-17","level":"early","profession":"education","title":"'His last teacher didn't do it this way'","scenario":"A parent pushes: 'His teacher last year let them retake every test. Why don't you?' Comparison questions bait you into judging a colleague or defending yourself. The answer is neither — it's your policy and its reason, delivered without a single word about last year.","task":"Write the 2-sentence spoken answer that stays on your policy.","tips":["Never grade another teacher's choices — sidestep and answer.","Give the reason your policy exists in terms of what it teaches.","One offered path ('corrections earn half back') shows the door isn't closed."],"focus":["clarity","audience"],"placeholder":"Every teacher builds this differently — here's how mine works and why."},
    {"id":"pressure-edu-early-18","level":"early","profession":"education","title":"Blanking on the number","scenario":"In the data meeting, the coach asks your class's median growth percentile. You presented it last month; right now it's gone. Five seconds of static, and the temptation is to say a number that's probably right. Probably is the trap.","task":"Write the spoken response: the honest blank, plus the commitment with a time.","tips":["'I don't want to give you a wrong number — I'll have it to you by 3:00.'","A confident 'I'll confirm' reads better than a shaky guess.","Then actually send it by 3:00; that's where the trust is built."],"focus":["clarity","concision"]},
    {"id":"pressure-edu-early-19","level":"early","profession":"education","title":"The grade challenge with an audience","scenario":"Handing back essays, a student loudly announces: 'This grading is rigged. Why did SHE get an A?' The class goes quiet. Comparing students' work publicly is the one door you can't open — but shutting him down without an answer breeds the rigged story.","task":"Write the spoken response: hold the privacy line, offer the real channel.","tips":["One calm line: 'I don't discuss anyone's grade with anyone else — including yours.'","Offer the legitimate path: see me after class with your rubric.","Deliver it level — the class is learning whether fairness has a process."],"focus":["clarity","impact"]},
    {"id":"pressure-edu-early-20","level":"early","profession":"education","title":"The screen-time skeptic","scenario":"At curriculum night, a parent asks pointedly: 'How much of the day are they just on tablets?' The premise smuggles in 'just.' The honest answer is 40 minutes with specific purposes — a fact that sounds different depending on whether you flinch.","task":"Write the spoken answer: the number, what it's for, what it's never for.","tips":["Give the number immediately — precision defuses the 'hiding something' energy.","Name the purposes: reading practice, math fluency — and the no-list: no videos, no games without a skill.","Answering a skeptical question calmly IS the reassurance."],"focus":["precision","audience"],"placeholder":"Forty minutes a day, in two blocks — and I can tell you exactly what happens in them."},
    {"id":"pressure-edu-early-21","level":"early","profession":"education","title":"The question you're not allowed to answer","scenario":"During your training session on the new HR system, someone asks whether the reorganization rumors are true. You've heard things in planning meetings you cannot share. A flustered 'no comment' confirms everything; a lie destroys you later.","task":"Write the 1-2 sentence spoken response that holds the line honestly.","tips":["Name your lane: 'I'm here on the system; org questions go to your director.'","Don't perform ignorance you don't have — redirect without confirming or denying.","Then move immediately to the next topic; lingering invites round two."],"focus":["clarity","audience"]},
    {"id":"pressure-edu-early-22","level":"early","profession":"education","title":"Thirty seconds with the superintendent","scenario":"The superintendent tours your classroom and asks, over the working hum: 'So what are they learning right now?' Not 'what's the activity' — what are they LEARNING. You have one sentence before her attention moves on.","task":"Write the 1-2 sentence spoken answer that names the learning, not the busywork.","tips":["Lead with the skill: 'They're learning to defend a claim with text evidence.'","Add the one detail that proves it's real: what you'll collect and check.","'They're doing a worksheet' is the answer that gets remembered wrong."],"focus":["clarity","impact"],"placeholder":"They're learning to back a claim with evidence from the text —"},
    {"id":"pressure-edu-early-23","level":"early","profession":"education","title":"'It's the phone, right?'","scenario":"A parent asks you to confirm her theory: 'His grades dropped because of that phone, right?' Maybe — but you actually see three things: missing sleep, a friend-group shift, and yes, the phone at lunch. Endorsing her single cause feels agreeable and closes the real inquiry.","task":"Write the spoken answer that stays calibrated without dodging.","tips":["Give what you observe, weighted honestly: 'The phone is part of it — here's what else I see.'","Resist over-claiming to bond with the parent; you'll own the claim later.","Recommend the next step that fits ALL the evidence."],"focus":["precision","audience"],"placeholder":"The phone is probably part of it — but two other things show up first from my seat."},
    {"id":"pressure-edu-early-24","level":"early","profession":"education","title":"Answering the question you actually heard","scenario":"At the board's public-comment session, a community member asks you a long, winding question about the reading program, and you genuinely lost the thread halfway. Answering the question you THINK it was risks a two-minute answer to the wrong thing.","task":"Write the spoken move: the clarifying restatement before any answer.","tips":["'Let me make sure I have it: you're asking whether...?' costs five seconds.","Restating earns thinking time and often softens the question.","Answering the wrong question convincingly is worse than pausing."],"focus":["clarity","structure"]},
    {"id":"pressure-edu-early-25","level":"early","profession":"education","title":"The book on trial","scenario":"At curriculum night, a parent holds up your class novel: 'Why is my child required to read THIS?' The room stills. You chose the book for defensible reasons, and the district approved it. The answer needs to be steady, brief, and end with the legitimate channel.","task":"Write the 3-sentence spoken response: the reason, the approval, the channel.","tips":["One sentence on why the book earns its place — the skill and theme it carries.","One on process: district-approved, alternative available on request.","Offer the one-on-one follow-up; a mic is the wrong venue for round two."],"focus":["structure","audience"],"placeholder":"We chose it because it's the strongest text we have for teaching perspective —"}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-edu-early-01","level":"early","profession":"education","title":"The pitch beyond 'kids will love it'","scenario":"You want $400 for flexible seating. Your draft to the principal says 'students would really benefit and be more engaged.' The stronger case is before/after: what your restless third period looks like now, and what the two classrooms that switched report.","task":"Write the 3-4 sentence pitch: before-picture, after-picture, and the cost of staying.","tips":["Open with the scene she'd recognize: the 1:40 fidget wave.","Borrow the after from real adopters — names and results.","End with the modest ask and the review date."],"focus":["impact","structure"],"placeholder":"By 1:40 every day, a third of my class is standing, leaning, or rocking their chairs."},
    {"id":"narrative-edu-early-02","level":"early","profession":"education","title":"One student beats a thousand words","scenario":"Your classroom-library grant application says 'many students lack access to high-interest books at home.' True, forgettable. What the committee will remember: the student who reread the same battered graphic novel five times because it's the only book he loves that he can reach.","task":"Write the application paragraph anchored on the one student.","tips":["One real, specific kid (anonymized) carries the whole abstract claim.","Follow the story with the number it represents: 14 of 26 students, zero books at home.","End with what the grant changes for that specific kid."],"focus":["impact","precision"],"placeholder":"One of my students has read the same graphic novel five times — not because he loves rereading,"},
    {"id":"narrative-edu-early-03","level":"early","profession":"education","title":"Selling ten minutes a night","scenario":"Your newsletter plea 'please read with your child nightly' has moved no one — it reads as one more obligation. The persuasive version paints the after: what changes by June for the kid who gets ten minutes a night, in terms a tired working parent can act on.","task":"Write the 3-4 sentence appeal that paints the payoff and shrinks the task.","tips":["Paint June: 'the difference between decoding and actually enjoying books.'","Shrink it: ten minutes, any book, even the same one again.","Address the real objection — exhaustion — by blessing the low-effort version."],"focus":["audience","impact"],"placeholder":"Ten minutes a night is the single biggest thing you can do — and it counts even when"},
    {"id":"narrative-edu-early-04","level":"early","profession":"education","title":"Filling the conference calendar","scenario":"Half your families skipped conferences last fall. Your sign-up announcement read like a scheduling notice. The families most likely to skip are the ones bracing for bad news — the message has to disarm that expectation before it asks for a time slot.","task":"Write the 3-sentence announcement that reframes what the meeting is and asks for the booking.","tips":["Reframe: ten minutes about YOUR kid, with the work in front of you — not a verdict.","Name the fear gently and retire it: this isn't a trouble meeting.","Make booking one step with a real link, and offer times outside work hours."],"focus":["audience","impact"],"placeholder":"Conferences are ten minutes with your child's actual work on the table — the good stuff included."},
    {"id":"narrative-edu-early-05","level":"early","profession":"education","title":"The rubric pitch and its objection","scenario":"You want your grade team to adopt one shared writing rubric. The strongest objection will come from the veteran: 'I've graded essays for twenty years without a committee rubric.' Your pitch has to answer her before she says it — or it dies in the meeting.","task":"Write the 3-4 sentence spoken pitch that includes the objection and your answer to it.","tips":["Raise the objection yourself: 'This isn't about anyone's judgment —'","The case: kids get the same targets in every room; parents stop comparing teachers.","Propose the two-assignment trial — small yes first."],"focus":["structure","impact"]},
    {"id":"narrative-edu-early-06","level":"early","profession":"education","title":"The PTA ask with stakes","scenario":"You're requesting $250 from the PTA for math manipulatives. Your draft lists the items. What's missing is the stakes: the kids who can't hold fractions in their heads yet, and what happens to them in April when the abstract unit arrives without the concrete one.","task":"Write the 3-sentence ask: the stakes, the fix, the exact amount.","tips":["Stakes first: what April looks like for a kid who never touched the concept.","The fix in one sentence — what the blocks actually do.","Exact amount, exact items; PTA boards fund specifics."],"focus":["impact","precision"],"placeholder":"In April, fractions go abstract — and the students who never held one in their hands are the ones who"},
    {"id":"narrative-edu-early-07","level":"early","profession":"education","title":"Recruiting the reluctant mathlete","scenario":"A quietly talented student won't join math club — 'that's for smart kids.' A lecture on her potential will bounce off. A story might not: the current club captain said the exact same sentence in this classroom two years ago.","task":"Write what you'd say to her in 3-4 spoken sentences, story first.","tips":["Tell the captain's before/after in two sentences — same words, same doubt.","Make the ask tiny: one Tuesday, sit in the back, leave whenever.","Let the story do the persuading; skip the 'you have potential' speech."],"focus":["audience","impact"]},
    {"id":"narrative-edu-early-08","level":"early","profession":"education","title":"The trip that isn't a day off","scenario":"Your principal sees field trips as lost instruction days, and you're proposing one to the wetlands center. The pitch that works isn't 'enriching experience' — it's the before/after on your ecosystems unit and a straight answer to the objection she'll actually raise: two missed class periods.","task":"Write the 3-4 sentence proposal with the objection answered inside it.","tips":["Tie the trip to the exact standard and the assessment it feeds.","Answer the time objection head-on: what the day replaces and why it's a trade up.","One logistical proof (coverage arranged, cost per kid) shows it's real."],"focus":["structure","audience"],"placeholder":"I want to trade two class periods for the wetlands center — here's the exchange rate."},
    {"id":"narrative-edu-early-09","level":"early","profession":"education","title":"The onboarding before-and-after","scenario":"You're a corporate trainer pitching your manager on rebuilding the onboarding course. Your draft lists its flaws. The version that gets funded tells a story: what a new hire's first week feels like now, and the same week after the redesign — with one number attached to each.","task":"Write the 3-4 sentence pitch as a before/after with the two numbers.","tips":["Before: day-three confusion, 40% still lacking system access. After: producing by Friday.","One new-hire quote makes the 'before' undeniable.","End with the ask: three weeks of your time and a pilot cohort."],"focus":["structure","impact"],"placeholder":"Right now, a new hire's first week ends with a login and a pile of PDFs — 40% still can't"},
    {"id":"narrative-edu-early-10","level":"early","profession":"education","title":"Reframing the reading group","scenario":"You're recommending reading support, and the parent hears one thing: my kid is the dumb kid now. The facts alone won't move her. What might: the story of what the group actually is — six kids, a teacher who does nothing else, and the fastest growth in the building.","task":"Write the 3-4 sentence spoken reframe that replaces the stigma story with the true one.","tips":["Name the fear before she does — 'most parents worry this is a label.'","Replace the picture: small table, specialist, thirty minutes, measurable exit criteria.","'Kids typically graduate out within a year' gives it an ending — labels don't have those."],"focus":["audience","impact"],"placeholder":"Most parents hear 'reading support' and picture a label. Here's what it actually looks like:"},
    {"id":"narrative-edu-early-11","level":"early","profession":"education","title":"The case for moving recess","scenario":"You want the schedule committee to move recess before lunch — research says kids eat more and settle faster. Your draft leads with three studies. Committees don't move for citations; they move for their own cafeteria at 12:15 and the after-picture at a nearby school.","task":"Write the 3-sentence spoken pitch: their current pain, the after, one study as a footnote.","tips":["Start in the shared misery: the 12:15 trash-can rush, untouched lunches.","The after-picture at a nearby school makes it feel adjacent, not utopian.","The research gets one clause of support, not the lead."],"focus":["audience","structure"],"placeholder":"You've all seen the 12:15 trash cans — full lunches, untouched, because recess is calling."},
    {"id":"narrative-edu-early-12","level":"early","profession":"education","title":"The thank-you that shows the money working","scenario":"A local business donated $300 for your class garden. Your draft thank-you says 'your generous support means so much.' What earns the NEXT donation: one scene of the money at work — the kid who wouldn't speak in group now explaining tomato-cage math to visitors.","task":"Write the 3-sentence thank-you with the scene in the middle.","tips":["One sentence of thanks, one scene, one sentence of what's next.","Impact is shown at the level of a single kid, not 'the students.'","Photos help; a scene in words survives being read aloud at their staff meeting."],"focus":["impact","audience"],"placeholder":"Your $300 became six raised beds — and something we didn't expect."},
    {"id":"narrative-edu-early-13","level":"early","profession":"education","title":"Selling revision to seventh graders","scenario":"Your students treat revision as punishment for writing it wrong the first time. Monday you're introducing revision week, and 'good writers revise' will bounce off. You have a better tool: draft one and draft four of the same paragraph — yours — from your own college essay.","task":"Write the 3-4 sentence spoken intro using your own before/after as the story.","tips":["Show your own bad first draft — nothing disarms a classroom faster.","Read the before and the after aloud; let the gap make the argument.","Reframe: revision isn't fixing failure, it's the part where writing gets good."],"focus":["audience","impact"]},
    {"id":"narrative-edu-early-14","level":"early","profession":"education","title":"The attendance letter without shame","scenario":"Your class's attendance dips every winter. The district's form letter threatens truancy referrals — and gets ignored. You're writing your own version. Shame doesn't move families; a concrete picture of what a missed Tuesday actually costs, plus an easy path back, might.","task":"Write the 3-4 sentence letter body: the concrete cost, zero shame, the easy path.","tips":["Make the cost specific: Tuesday is the day the new math skill lands; miss it and Wednesday is fog.","Strike every scolding phrase; write like an ally with information.","End with the offer: tell us the barrier — bus, mornings, laundry — and we'll problem-solve it."],"focus":["audience","impact"],"placeholder":"Here's what a missed Tuesday actually costs: it's the day the week's new math skill is taught."},
    {"id":"narrative-edu-early-15","level":"early","profession":"education","title":"Why this class matters, in one story","scenario":"You teach middle-school science and get four minutes at back-to-school night. Last year you listed units and lost the room by minute two. This year you'll open with one story — the student who tested the 'five-second rule' for her fair project — and let it carry the 'why.'","task":"Write the opening 3-4 spoken sentences: story first, then what it says about the year.","tips":["The story should show a kid THINKING, not a kid complying.","Bridge from story to promise: this is what your child does here all year.","Parents remember one kid and one idea — build the four minutes around them."],"focus":["impact","audience"]},
    {"id":"narrative-edu-early-16","level":"early","profession":"education","title":"Persuading the teacher next door","scenario":"Your hand-signal system killed the constant bathroom-and-water interruptions. Your teammate complains about interruptions daily, but 'you should try my system' triggers her skepticism of anything from a first-year teacher. Lead with HER problem and the story of your Tuesday, not your system.","task":"Write the 2-3 sentence spoken pitch, her problem first, your evidence second.","tips":["Open inside her complaint: 'You know the eight-hands thing during minilessons?'","One before/after number from your room: eight interruptions down to one.","Offer it small: a photo of the poster, not a philosophy."],"focus":["audience","concision"],"placeholder":"You know how you said the interruptions are eating your minilessons? I counted mine: eight a lesson, down to about one."},
    {"id":"narrative-edu-early-17","level":"early","profession":"education","title":"The behavior plan as a shared story","scenario":"You're proposing a behavior contract, and the parent across the table is braced for her son to be cast as the problem child. The contract survives only if the story changes: not 'your kid is broken' but 'here's the kid we both see at his best, and the plan that gets more of him.'","task":"Write the 3-sentence spoken framing that opens the conversation.","tips":["Open with the best-self scene: Tuesday, the science demo, him leading.","Frame the plan as engineering more of THAT kid, not policing the other one.","Ask what she sees at home first — co-authors, not defendants."],"focus":["audience","impact"],"placeholder":"Before we talk about a plan, I want to tell you about Tuesday, because I saw the version of Malik we're aiming for."},
    {"id":"narrative-edu-early-18","level":"early","profession":"education","title":"Filling the optional workshop","scenario":"You're a corporate trainer whose optional 'Difficult Conversations' workshop drew four people last quarter. The invite read like HR compliance. The rewrite has to sell the after: the manager who used the script two days later to finally address the missed-deadline pattern poisoning her team.","task":"Write the 3-sentence invitation built on that story.","tips":["Open with the after-story: real manager, real conversation, two days later.","Promise the artifact: leave with a script for YOUR stuck conversation.","Cut every word that smells like compliance."],"focus":["impact","audience"],"placeholder":"A manager left this workshop in March and finally had the conversation she'd postponed for a year — two days later."},
    {"id":"narrative-edu-early-19","level":"early","profession":"education","title":"Protecting the planning period","scenario":"You've covered other classes during your planning period six times this month, and quality is slipping where it counts. Asking the principal to stop assigning you feels like complaining. Framed as stakes — what those 45 minutes buy her students — it's a case.","task":"Write the 3-sentence case: what planning produces, what six coverages cost, the ask.","tips":["Translate planning time into student-visible outputs: differentiated groups, graded-with-feedback essays.","Numbers make it unemotional: six coverages, four ungraded sets.","Ask for the specific policy: last resort, not first call."],"focus":["structure","impact"],"placeholder":"Six coverage assignments this month cost my students four days of feedback — here's the connection."},
    {"id":"narrative-edu-early-20","level":"early","profession":"education","title":"The volunteer ask that shows the shift","scenario":"'We need classroom volunteers!' has run in three newsletters and produced one grandmother. Parents can't say yes to fog. What they can say yes to: a picture of the actual shift — Tuesday, 9:00-9:45, sit at the blue table, listen to three kids read, done.","task":"Write the 3-sentence recruitment blurb that paints the exact shift.","tips":["Describe one concrete shift, minute by minute — yes-able is specific.","Kill the fear: no prep, no grading, we train you in five minutes.","One volunteer quote ('best 45 minutes of my week') outperforms any plea."],"focus":["audience","precision"],"placeholder":"Here's what volunteering actually is: Tuesday, 9:00-9:45, the blue table, three kids reading to you."},
    {"id":"narrative-edu-early-21","level":"early","profession":"education","title":"The homework pitch and the rigor objection","scenario":"You want your team to replace the nightly worksheet packet with read-plus-one-problem. The objection you'll face: 'we're lowering the bar.' If your pitch doesn't answer that word — rigor — before it's spoken, the meeting will end with the packet intact.","task":"Write the 3-4 sentence spoken pitch that redefines the bar before defending the change.","tips":["Claim rigor for your side first: the packet measures compliance; one strong problem measures thinking.","Data point: how many packets come back copied or blank.","Propose the one-unit trial with a check: quiz scores, not vibes."],"focus":["structure","impact"]},
    {"id":"narrative-edu-early-22","level":"early","profession":"education","title":"'But it's just comics'","scenario":"A parent is worried her son 'only reads graphic novels' and wants him forced onto chapter books. You have a better story: this is the first year he's read daily by choice, and the research on visual texts is on your side. The persuasion is her goal — a kid who loves reading — already coming true.","task":"Write the 3-sentence spoken response that reframes what she's seeing.","tips":["Start at the shared goal: a kid who reads without being made to. He is one, now.","One fact about graphic novels' vocabulary load surprises most parents.","Give the bridge plan: series that walk from panels to prose."],"focus":["audience","impact"],"placeholder":"Here's what I see: this is the first year Diego reads every single day without anyone making him."},
    {"id":"narrative-edu-early-23","level":"early","profession":"education","title":"The June book drive","scenario":"You're asking families to donate used books for next year's classroom library. 'Donations welcome!' will produce three books and a broken puzzle. The version that fills a shelf tells families exactly what happens to the book their kid outgrew: whose hands it lands in come September.","task":"Write the 3-sentence appeal with the after-picture and the precise ask.","tips":["Paint September: a new second grader finding your kid's old favorite.","Be precise about the want-list: picture books and early chapter books, gently used.","Logistics in one line: the bin by the office, through June 12."],"focus":["impact","concision"],"placeholder":"That chapter book your child outgrew this year? In September it becomes some new second grader's first favorite."},
    {"id":"narrative-edu-early-24","level":"early","profession":"education","title":"Selling summer school as a running start","scenario":"You're recommending summer math camp, and the family hears 'summer school' — punishment, failure, a ruined July. It's actually mornings-only, games-heavy, and the kids who go start September ahead instead of behind. The story you tell in this meeting decides whether he shows up.","task":"Write the 3-4 sentence spoken pitch that replaces the punishment story.","tips":["Rename the experience by describing it: mornings, small group, math through games, done by noon.","The after: he starts the year already knowing the first unit — that's a different September.","One alum story ('a student last year came back and led the first unit') seals it."],"focus":["audience","impact"],"placeholder":"Forget the words 'summer school' — let me describe what it actually is."},
    {"id":"narrative-edu-early-25","level":"early","profession":"education","title":"Getting families to literacy night","scenario":"Last year's family literacy night drew nine people in a school of 400. The flyer said 'Join us for an evening of literacy activities!' — an invitation to nothing in particular. This year's flyer has one job: make a busy family choose this over a normal Thursday night.","task":"Write the 3-sentence flyer copy: what they'll actually do, what they leave with, why their kid wants them there.","tips":["Concrete over festive: make-and-take word games, free pizza at 5:30, books to keep.","'Your child performs at 6:15' is the strongest attendance driver in schools.","One logistical kindness — siblings welcome, done by 7 — removes the last excuse."],"focus":["audience","impact"],"placeholder":"Thursday at 5:30: pizza, then your child teaches YOU the word game their class invented."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-edu-early-01","level":"early","profession":"education","title":"The summer-school conversation","scenario":"You have to tell parents their daughter needs summer school to be ready for fourth grade. Your draft opens with three paragraphs about her artwork and kindness before the news arrives, softened into invisibility. Clear is kind; buried is cruel later.","task":"Write the first 2 sentences of the conversation, headline first, warm but unmistakable.","tips":["The news in sentence one: she needs summer support to be ready for fourth grade.","Warmth lives in tone and the plan — not in delay.","Vagueness now becomes 'why didn't anyone tell us' in August."],"focus":["clarity","audience"],"placeholder":"I need to share something important: based on this spring's progress, Kayla needs summer school to be ready for"},
    {"id":"hard-edu-early-02","level":"early","profession":"education","title":"No to the daily report","scenario":"A parent asks you to email her a daily behavior report on her son. You have 26 students; a daily custom email is not sustainable, and saying 'I'll try' guarantees resentment in three weeks. The honest answer is no — with a system you CAN sustain.","task":"Write the reply: the clean no, the reason, the workable alternative.","tips":["Decline the specific thing plainly — 'I can't commit to daily emails.'","The reason is math, not unwillingness: say it without apology.","Offer what's real: a Friday note plus immediate contact for anything serious."],"focus":["clarity","audience"],"placeholder":"I can't commit to a daily email — with 26 students it's a promise I'd break within weeks. Here's what I can do reliably:"},
    {"id":"hard-edu-early-03","level":"early","profession":"education","title":"The comment that tells the truth","scenario":"Report-card comments are due, and your draft for a struggling student says he 'is working hard and making progress' — which is half true and fully misleading. His parents will be blindsided at the March meeting if the paper trail says everything's fine.","task":"Write the 2-sentence comment that is honest about the struggle and names the support.","tips":["Pair the truth with the plan: 'reading below grade level; daily small-group support.'","Kind specifics beat kind fog — fog reads as fine.","The report card is a record; write what March-you needs it to have said."],"focus":["clarity","precision"],"placeholder":"Jaden is reading below grade level and receives daily small-group support."},
    {"id":"hard-edu-early-04","level":"early","profession":"education","title":"Killing your own pilot","scenario":"You championed the app-based spelling pilot to your principal in September. It's February and the data is in: scores flat, kids gaming the points system. Telling her means admitting your pick failed — but she needs the truth before the district asks about renewal money.","task":"Write the 3-sentence update: the verdict, the evidence, your recommendation.","tips":["Lead with the verdict — don't make her excavate it from caveats.","The data is the message: flat scores, two examples of gaming.","Recommending against your own pick is credibility in the bank."],"focus":["clarity","impact"],"placeholder":"I want to be straight about the spelling pilot: it isn't working, and I don't recommend renewing."},
    {"id":"hard-edu-early-05","level":"early","profession":"education","title":"The cheating call","scenario":"Two students turned in identical paragraphs, and the document history shows whose came first. You're calling the parents of the student who copied. The word 'cheating' will detonate — but softening it into 'academic similarity concerns' hides the thing they need to address.","task":"Write your opening 2-3 spoken sentences: factual, calm, no euphemism, no verdict on character.","tips":["Describe the evidence, not the child: 'the paragraphs are identical, and the edit history shows...'","Name it plainly once — copying — then move to what happens next.","Separate act from identity: this is a thing he did, not who he is."],"focus":["clarity","precision"],"placeholder":"I'm calling about something specific: Tyler's essay paragraph is identical to another student's, and the document history shows"},
    {"id":"hard-edu-early-06","level":"early","profession":"education","title":"The volunteer who took over","scenario":"A devoted parent volunteer has started correcting students' behavior and re-teaching your math methods her own way at her table. She donates three mornings a week and means well. The conversation has to land one boundary without losing the help.","task":"Write the 2-3 sentence spoken message: appreciation that's true, the boundary, the redirect.","tips":["The boundary in plain words: instruction and discipline stay with me.","Give her a bigger version of the RIGHT job — she has energy; aim it.","Don't trade a clear boundary for politeness; you'll be back in a month."],"focus":["audience","clarity"],"placeholder":"I want to keep you three mornings a week forever — and I need one adjustment."},
    {"id":"hard-edu-early-07","level":"early","profession":"education","title":"The no that protects your prep","scenario":"The office asks you — for the third time this month — to cover a class during your only prep period. Each yes made the next ask more automatic. Today's no needs to be clean enough to reset the pattern without torching goodwill.","task":"Write the 1-2 sentence spoken no.","tips":["No plus the reason once: 'I can't today — this prep is holding my IEP paperwork deadline.'","Don't offer a fake maybe; it re-opens the negotiation.","One reliable no teaches the office to check the rotation first."],"focus":["clarity","concision"]},
    {"id":"hard-edu-early-08","level":"early","profession":"education","title":"Feedback for your TA","scenario":"Your teaching assistant is wonderful with kids and on her phone during independent work — the exact stretch when three students need redirection. You're her supervisor, five years her junior, and you've never given corrective feedback to anyone. Vague hints haven't worked.","task":"Write the 2-3 sentence spoken feedback: specific behavior, specific impact, specific ask.","tips":["Name the exact window: independent work, 10:15-10:45, phone out.","Impact, not character: those are the minutes Marcus and Dee lose focus.","The ask is concrete: phone in the drawer during that block."],"focus":["precision","clarity"],"placeholder":"During independent work — the 10:15 block — I need your eyes on the room, and lately the phone's been winning."},
    {"id":"hard-edu-early-09","level":"early","profession":"education","title":"Your child was the one","scenario":"After a week of investigation, it's clear: this parent's daughter has been the one excluding and mocking a classmate — not the victim, as the parent believes. The call you're making will collide with the story they've been told at home. Facts, not adjectives, survive that collision.","task":"Write your opening 2-3 spoken sentences.","tips":["Lead with why you're calling, then the specific observed behaviors with dates.","Skip labels like 'bully' — describe actions; let them carry the weight.","State the next step and the partnership ask before feelings flood the line."],"focus":["clarity","audience"],"placeholder":"I'm calling about something hard: over the past two weeks, I've directly observed Emma"},
    {"id":"hard-edu-early-10","level":"early","profession":"education","title":"The cast list conversation","scenario":"You directed the school play auditions, and the eighth grader who wanted the lead — who told everyone she'd get it — is cast in the ensemble. She's coming to ask why. The kind lie ('it was so close!') if false sets up next year's harder fall.","task":"Write the 2-3 sentence spoken answer: the truth, the reason, the real path forward.","tips":["Honest and specific: what the casting decision turned on.","No inflation of how close it was, if it wasn't.","End with what would change the outcome next time — that's the gift."],"focus":["clarity","impact"]},
    {"id":"hard-edu-early-11","level":"early","profession":"education","title":"The timeline that isn't real","scenario":"Your client wants the compliance training built and delivered in two weeks. It's a five-week build if it's going to work. Saying yes and delivering something hollow protects this month's relationship and destroys next quarter's. The no has to come with the math.","task":"Write the 3-sentence reply: the no, the math, the two real options.","tips":["'Two weeks isn't achievable for this scope' — no hedging.","Show the math briefly: what the build actually requires.","Options preserve their control: smaller scope in two weeks, or full scope in five."],"focus":["clarity","structure"],"placeholder":"I can't deliver this well in two weeks, and I'd rather tell you now than on day thirteen."},
    {"id":"hard-edu-early-12","level":"early","profession":"education","title":"Breaking it to the class","scenario":"The overnight camping trip your fourth graders have talked about since September is canceled — the venue closed. You're telling 26 kids at morning meeting. Hedging ('we'll see, maybe, possibly') breeds a week of hopeful rumors that end in the same disappointment, twice.","task":"Write the 3-sentence spoken announcement: the news, the honest reason, what happens instead.","tips":["Say it straight in sentence one — kids handle news better than wobble.","One honest reason; skip the adult logistics saga.","The replacement plan goes in the SAME breath, and it must be real."],"focus":["clarity","audience"]},
    {"id":"hard-edu-early-13","level":"early","profession":"education","title":"The co-teacher conversation","scenario":"Your co-teacher arrives ten minutes late most mornings, leaving you solo for the arrival rush and the day's setup. You've absorbed it for two months and it's curdling into resentment. She outranks you in seniority; the conversation still has to happen — about the pattern, not her character.","task":"Write the 2-3 sentence spoken opener.","tips":["Pattern plus impact: 'most mornings this month' plus what the solo rush costs kids.","No diagnosis of her life — just the schedule and the need.","Ask for the specific fix and offer flexibility on the how."],"focus":["clarity","audience"],"placeholder":"Can I raise something before it gets weird? Most mornings I'm solo until 8:10, and arrival is the stretch where"},
    {"id":"hard-edu-early-14","level":"early","profession":"education","title":"The recommendation you can't write","scenario":"A former student asks you for a program recommendation letter. He was chronically disengaged in your class, and the honest letter would hurt him. A glowing lie would spend your credibility. The kind move is a fast, clean decline that leaves him time to ask someone better positioned.","task":"Write the 2-3 sentence reply.","tips":["Decline quickly — a slow no steals his application window.","'I don't think I'm the right person to make your strongest case' is true and humane.","Point him toward who could write the stronger letter."],"focus":["audience","clarity"],"placeholder":"I'm going to be straight with you: I don't think I'm the person to make your strongest case."},
    {"id":"hard-edu-early-15","level":"early","profession":"education","title":"The canceled trip email","scenario":"The zoo trip is canceled — bus costs doubled and the budget broke. Families paid deposits and kids are excited. Your draft buries the cancellation under two paragraphs of context about district transportation contracts nobody asked for.","task":"Write the 3-sentence email: the news, the refund logistics, the replacement.","tips":["Cancellation and refund in the first two sentences — that's what families scan for.","One clause of reason; the procurement saga is not their problem.","A concrete replacement ('a zoo educator visits our classroom May 8') softens honestly."],"focus":["clarity","structure"],"placeholder":"The May 3 zoo trip is canceled — bus costs doubled and our budget can't cover it. Your $10 deposits will be refunded"},
    {"id":"hard-edu-early-16","level":"early","profession":"education","title":"The progress report without progress","scenario":"At the IEP review, your data shows the reading goal hasn't moved in twelve weeks. The parents across the table are hopeful and tired. Fudging the trend line steals the urgency this meeting exists to create — the plan needs changing, and only honest data forces that.","task":"Write the 2-3 spoken sentences that present the flat data and pivot to changing the plan.","tips":["State the data plainly: twelve weeks, no measurable movement.","Immediately own the implication: the current approach isn't working — not the child.","Pivot to action: here's what I want to try differently, starting now."],"focus":["precision","impact"],"placeholder":"I'm going to show you the honest picture: twelve weeks of data, and the goal hasn't moved."},
    {"id":"hard-edu-early-17","level":"early","profession":"education","title":"The project that doesn't qualify","scenario":"A student proudly shows you his science-fair board two days before the fair. It's a report about volcanoes — no question, no experiment, no data. It doesn't meet requirements, and he worked hard on the wrong thing. Two days is enough to fix it, but only if you tell him now, clearly.","task":"Write the 2-3 sentence spoken message: the problem, what stays, the 48-hour path.","tips":["Name the gap precisely: it needs a question and a test, and it has neither yet.","Salvage first: the research becomes the background section.","The rescue plan must fit 48 real hours — offer the simplest qualifying experiment."],"focus":["clarity","structure"]},
    {"id":"hard-edu-early-18","level":"early","profession":"education","title":"Peer feedback that says something","scenario":"You observed a colleague's lesson as part of the peer program, and the discussion portion lost the class — six kids talking, twenty checked out. The easy writeup is all compliments. She asked for real feedback, and 'it was great!' wastes her request and your hour.","task":"Write the 2-sentence feedback: one genuine strength, one specific growth area with a suggestion.","tips":["The strength must be as specific as the critique — earned, not cushioning.","Critique the design, not the teacher: 'the discussion format let six voices carry it.'","Attach one concrete move: cold-call cards, turn-and-talks, written entry tickets."],"focus":["precision","audience"],"placeholder":"Your opening hook was the best I've seen this year — genuinely. The discussion is where I'd push:"},
    {"id":"hard-edu-early-19","level":"early","profession":"education","title":"Pushing back on your mentor","scenario":"Your assigned mentor keeps advising you to run her exact classroom-management system. You've tried it for a month; it fights your style, and your behavior log says your modified version works better. Deference has kept you silent. The relationship can survive the truth; your classroom can't survive the silence.","task":"Write the 2-3 sentence spoken message: gratitude that's real, the disagreement, the evidence.","tips":["Thank her for the system's parts that DID work — specifically.","Disagree with data, not preference: the log from both months.","Frame it as your development, which is literally her job's goal."],"focus":["clarity","impact"]},
    {"id":"hard-edu-early-20","level":"early","profession":"education","title":"Announcing the mid-year change","scenario":"You're the departing teacher: a family move means you leave at winter break, mid-year. The families know nothing yet; kids will take their cue from how the adults frame it. Your letter has to deliver the news without drama, honor the relationship, and make the transition feel planned rather than abandoned.","task":"Write the first 3 sentences of the letter to families.","tips":["News first, reason in one clause, no apology spiral.","The transition plan is the reassurance: who, when, what stays the same.","Keep your grief out of the first paragraph; the letter is for them."],"focus":["clarity","audience"],"placeholder":"I'm writing to share some news: my family is moving in January, and my last day will be December 19."},
    {"id":"hard-edu-early-21","level":"early","profession":"education","title":"Ending the tutoring arrangement","scenario":"You've tutored a student after school, unpaid, twice a week since October. It's now consuming your grading time and you're stretched thin. The family has come to rely on it. The message has to end the arrangement cleanly — a fade-out of canceled sessions would be worse.","task":"Write the 3-sentence message: the end date, the reason in brief, the handoff options.","tips":["A real end date beats an indefinite 'less often.'","One honest reason, no guilt essay — capacity is a valid reason.","The handoff is the care: the homework club schedule, two tutor referrals."],"focus":["clarity","structure"],"placeholder":"After November, I won't be able to continue our Tuesday and Thursday sessions."},
    {"id":"hard-edu-early-22","level":"early","profession":"education","title":"Coaching the boss's presentation","scenario":"You're a corporate trainer, and a department manager — senior to you — asked for honest feedback on his all-hands presentation. It was a wall of text read aloud in a monotone; people were on laptops by slide four. He asked. Flattery would be the actual insubordination.","task":"Write the 2-3 sentence spoken feedback: strength, the one big fix, the offer.","tips":["Pick the ONE change with the highest payoff — don't unload the full list.","Describe what the audience did, not what he is: 'laptops opened around slide four.'","Offer the concrete rebuild: cut to one line per slide, tell the Q3 story out loud."],"focus":["audience","impact"],"placeholder":"You asked for honest, so here it is: the content is strong, and the slides are burying it."},
    {"id":"hard-edu-early-23","level":"early","profession":"education","title":"Declining the committee","scenario":"The principal asks you to join the schedule committee — your third committee invitation this year. New teachers fear that no reads as not-a-team-player. But your evenings are already IEP paperwork and first-year planning, and a burned-out yes serves no one.","task":"Write the 2-sentence reply: the no, and the yes you can afford.","tips":["Decline the role, affirm the mission: 'I can't take a committee seat this year.'","Offer the bounded alternative: feedback on drafts, one working session.","No justification essay — one reason, stated once, is plenty."],"focus":["concision","clarity"],"placeholder":"I need to say no to a committee seat this year — my first-year plate is at capacity."},
    {"id":"hard-edu-early-24","level":"early","profession":"education","title":"Raising the evaluation question","scenario":"You've taught this student for seven months, tried three levels of support, and documented all of it. It's time to recommend a formal learning evaluation — words that will land on his parents like a diagnosis. The message must be honest about your concern without practicing medicine.","task":"Write the 2-3 spoken sentences that recommend the evaluation.","tips":["Ground it in what you've tried and observed — the documented pattern is the reason.","An evaluation is information, not a verdict: say that sentence explicitly.","Stay in your lane: describe learning behaviors, never name suspected conditions."],"focus":["audience","precision"],"placeholder":"We've tried three levels of support since October, and the pattern tells me it's time for better information."},
    {"id":"hard-edu-early-25","level":"early","profession":"education","title":"The mistake was yours","scenario":"You misread the district calendar and told all your families the wrong date for the spring concert. Some booked time off work for the wrong night. The correction email needs the fix in the first line and the ownership right behind it — not a passive 'an error occurred.'","task":"Write the 3-sentence correction email.","tips":["Correct date first, in bold if the platform allows.","'I gave you the wrong date — that was my error' — active voice, one sentence.","Acknowledge the real cost (rebooked shifts) and what you've changed."],"focus":["clarity","impact"],"placeholder":"Correction: the spring concert is Thursday, May 21 — not the 14th as I wrote. That error was mine."}
  ],
  "putting-it-together": [
    {"id":"together-edu-early-01","level":"early","profession":"education","title":"One closure, two channels","scenario":"A burst pipe closed your wing, and Monday's classes relocate to the gym. You owe two messages: a complete email to families tonight and a 25-word class-app alert for the 7am phone-checkers. Same facts, radically different shapes.","task":"Write both: the 3-sentence email and the one-line alert.","tips":["The alert carries only what changes a parent's morning: where, what to bring.","The email carries the rest: why, how long, lunch logistics.","The facts must match exactly across both — drift creates phone calls."],"focus":["audience","concision"],"placeholder":"ALERT: Room 114 classes meet in the GYM all week. Drop-off unchanged."},
    {"id":"together-edu-early-02","level":"early","profession":"education","title":"The welcome letter, stranger-tested","scenario":"Your first-day welcome letter is drafted. Now read it as its real readers will: a family new to the country, a grandmother raising her grandson, a parent skimming at a red light. Where does it assume knowledge nobody gave them? What's missing that they'll have to email about?","task":"List the 3 reader-side checks you'd run on the letter and what each catches.","tips":["Check one: every school-specific term (specials, dismissal numbers) — defined or cut?","Check two: can a skimmer extract the three actions and dates in 15 seconds?","Check three: does it answer the first-week panic questions — lunch, pickup, what to bring?"],"focus":["audience","structure"]},
    {"id":"together-edu-early-03","level":"early","profession":"education","title":"Four minutes, every skill","scenario":"Back-to-school night gives you four minutes with families. Everything converges: lead with what matters most, know your audience (anxious, busy, phones buzzing), one concrete example of the year's work, clear structure they can follow, and an ending that tells them exactly how to reach you.","task":"Write the 4-5 sentence spoken talk.","tips":["Open with the promise of the year in one sentence — not your bio.","One vivid specific (the September-to-June writing sample wall) beats five program names.","Close on the action: how to reach you, and the one thing to do this week."],"focus":["structure","impact"],"placeholder":"By June, your child will read chapter books and write a page that sounds like them — here's how we get there."},
    {"id":"together-edu-early-04","level":"early","profession":"education","title":"The incident email, complete","scenario":"A student threw a chair in class today; no one was hurt, the class evacuated calmly for ten minutes, and other families will hear versions at dinner. Your email to all families needs everything at once: headline first, facts precise, privacy held, tone steady, next steps clear — in under 150 words.","task":"Write the email.","tips":["BLUF: what happened and that everyone is safe, sentence one.","Facts a camera would agree with; zero details identifying the student.","Close with what happens next and how to reach you — then stop writing."],"focus":["structure","audience"],"placeholder":"I want you to hear from me directly: during math today, a student threw a chair. No one was hurt."},
    {"id":"together-edu-early-05","level":"early","profession":"education","title":"The last email of the year","scenario":"Your end-of-year email to families wants to do six things: celebrate, thank, collect library books, preview next year, say goodbye to leavers, and share the summer packet. Six things means nothing lands. The skill is choosing a lead, ordering the rest, and cutting what a June inbox won't read.","task":"Write the email's first 3 sentences and list the order of the remaining items.","tips":["Pick the emotional lead — the year's one sentence — then get logistical fast.","Actions before sentiments in the body: books due, packet linked.","Cut at least one thing entirely; June attention is a scarce resource."],"focus":["structure","concision"],"placeholder":"What a year: in September, half of us couldn't write a paragraph — this month I read 26 personal essays."},
    {"id":"together-edu-early-06","level":"early","profession":"education","title":"'Tell us about yourself'","scenario":"The interview for your first full-time post opens with the classic: 'Tell us about yourself.' Sixty seconds, an unstructured invitation, everything you've practiced in one answer: lead with the point, shape it (past-present-future), one proof story, land on why THIS school.","task":"Write the 60-second spoken answer (4-5 sentences).","tips":["One sentence of identity-as-teacher first — your thesis.","Past, present, future is a spine the panel can follow at 4pm on interview day.","End on them: the specific thing about this school your work connects to."],"focus":["structure","impact"],"placeholder":"I'm a teacher who came to it through tutoring — I discovered I love the moment a kid stops guessing."},
    {"id":"together-edu-early-07","level":"early","profession":"education","title":"After the lockdown drill","scenario":"Today's lockdown drill ran long, and kids came home with fragments: 'we hid in the dark for a while.' Tonight's note to families has competing jobs — inform, calm, explain the why, invite questions — and one hard constraint: it must not be scarier than the drill was.","task":"Write the 3-4 sentence note.","tips":["First sentence: it was a planned drill, everyone did fine — headline over suspense.","Explain what kids experienced in concrete, boring terms; boring is calming.","Give parents the conversation starter for home and a channel for questions."],"focus":["audience","clarity"],"placeholder":"Today we ran a planned lockdown drill — everyone did exactly what they practiced, and all is well."},
    {"id":"together-edu-early-08","level":"early","profession":"education","title":"The ten-minute conference, designed","scenario":"Conferences are Thursday: ten minutes per family, 24 slots, no overruns. The design is the skill — an opening that sets the map, evidence over adjectives, the hard part on schedule, an ending that assigns the next step. Design it once; run it 24 times.","task":"Write your conference script skeleton: the opening line, the three segment topics with minutes, and the closing line.","tips":["Announce the shape out loud — it gives you permission to keep time.","Put the growth area at minute 4, not minute 9 — hard things need airtime.","The closing line assigns one action each: yours, theirs, the child's."],"focus":["structure","concision"],"placeholder":"We have ten minutes, so here's my plan: two on strengths, four on the one thing we're working on, and"},
    {"id":"together-edu-early-09","level":"early","profession":"education","title":"The newsletter, rebuilt","scenario":"Your weekly newsletter has everything wrong at once: buried action items, edu-jargon, five paragraphs where five lines would do, no consistent structure week to week. You're rebuilding the template using the whole toolkit — one format that works every Friday.","task":"Design the template: name its 4 sections in order and write the one-line rule for each.","tips":["Section one is actions-with-dates; parents may read nothing else.","A repeated structure trains families where to look — consistency IS the feature.","Give the fun narrative a section too, last, for those who scroll."],"focus":["structure","audience"],"placeholder":"Section 1 — DO THIS: every date and action item, one line each, bolded."},
    {"id":"together-edu-early-10","level":"early","profession":"education","title":"Self-edit against the rubric","scenario":"Your memo to the principal requesting a schedule change is drafted — 400 words. Before sending, run the full check: point first? One idea per paragraph? Every claim evidenced? Cuttable words cut? Reader's objection answered? You find it fails three of five.","task":"List the five checks in the order you'd run them and name the fix each one typically forces.","tips":["Check the lead first — most drafts hide the ask in paragraph three.","The concision pass goes LAST; no point polishing sentences you'll delete.","Read it once as the principal: what would make her say 'but what about...?'"],"focus":["structure","concision"]},
    {"id":"together-edu-early-11","level":"early","profession":"education","title":"Two minutes at the staff meeting","scenario":"You got two minutes on the staff-meeting agenda to propose a shared morning-arrival routine for your hallway. The full stack, spoken: the point first, evidence in one breath, the objection pre-answered, a specific ask with a date, all in a voice that sounds decided.","task":"Write the 5-sentence spoken proposal.","tips":["Sentence one is the proposal itself — not the backstory.","Pre-answer the objection you'd raise if you were them: setup burden.","End with the exact next step: pilot starts Monday, sign the sheet."],"focus":["structure","impact"],"placeholder":"Proposal: one shared arrival routine for our hallway — same greeting, same board format, same first five minutes."},
    {"id":"together-edu-early-12","level":"early","profession":"education","title":"The wrap-up email three audiences read","scenario":"Your training program just ended, and one wrap-up email goes to the sponsor VP (cares: was it worth it), the participants' managers (care: what changes now), and the participants (care: what's next for them). One email, three readers, every skill at once.","task":"Write the email's structure: the subject line, the opening sentence, and the three labeled sections.","tips":["The opening sentence must serve the VP — results, in numbers.","Labeled sections let each reader self-serve: Results / What to expect / Your next steps.","Anything relevant to only one audience goes in that section, not the intro."],"focus":["audience","structure"],"placeholder":"Subject: Feedback-skills program complete — 94% completion, manager actions inside"},
    {"id":"together-edu-early-13","level":"early","profession":"education","title":"One student, three readers","scenario":"You're writing about the same struggling-but-growing student three times this week: a report-card comment (parents), a handoff note (next year's teacher), and a sticky note on his desk (him, age nine). Same truth, three registers — a triangulation exercise in audience.","task":"Write all three: the 2-sentence comment, the 1-sentence handoff, the sticky note.","tips":["Parents get warmth plus data; the teacher gets the operative fact plus what works.","The sticky note is seven words a nine-year-old rereads.","Check the three against each other: same kid? Then they're honest."],"focus":["audience","precision"],"placeholder":"For parents: Owen's reading grew two levels this year, and he did it by refusing to quit on hard books."},
    {"id":"together-edu-early-14","level":"early","profession":"education","title":"The draft you don't send","scenario":"A parent's email accused you of 'not caring about kids' — over a recess consequence. Your reply draft is written and it is magnificent and you cannot send it. The rewrite needs everything: de-escalated register, facts over feelings, one boundary held, an off-ramp to a meeting.","task":"Write the 3-sentence reply that replaces the magnificent draft.","tips":["Delete every sentence that exists to win; keep the ones that resolve.","One plain factual account of the consequence, no adjectives.","Move it to person or phone — heat dies in synchronous channels."],"focus":["audience","clarity"],"placeholder":"I can hear how angry you are, and I'd rather resolve this than trade emails. Here's what happened at recess:"},
    {"id":"together-edu-early-15","level":"early","profession":"education","title":"Sub plans a stranger can run","scenario":"You'll be out three days for a family matter — the longest a sub has run your room. The plans are a complete communication test: prioritized (what MUST happen vs. nice-to-have), audience-aware (she's never met these kids), precise (names, times, locations), and skimmable at 7:45am.","task":"Write the plans' first section: the top-priority box (3 items) and the one-paragraph room orientation.","tips":["The must-do box goes first and stays under three items — real priorities, not everything.","Write the orientation for someone with ten minutes and no context: allies, tricky moments, where things live.","Name the two students who help and the one routine that anchors the class."],"focus":["structure","precision"],"placeholder":"READ THIS FIRST — three things that must happen: 1) Deon takes medication at the nurse, 11:30 sharp."},
    {"id":"together-edu-early-16","level":"early","profession":"education","title":"The grant in 150 words","scenario":"The education-foundation grant form gives you 150 words for 'describe your project and its impact.' Your draft is 410. The compression is the whole game: the stakes concrete, one student visible, the number exact, the ask unmistakable — and 260 words gone.","task":"Write the 150-word-or-fewer project description.","tips":["One kid, one number, one ask — the trinity survives any word count.","Cut the history of how you got the idea; funders buy the future.","Read the final version aloud once; compressed shouldn't mean airless."],"focus":["concision","impact"],"placeholder":"Fourteen of my 26 students have no books at home. This grant buys 120"},
    {"id":"together-edu-early-17","level":"early","profession":"education","title":"The voicemail and its echo","scenario":"You need to reach a parent about scheduling a support meeting — she answers neither channel reliably, so you're sending both a voicemail and an email. The pair is a system: the voicemail carries urgency and warmth in 20 seconds; the email carries the details and the record.","task":"Write both: the 20-second voicemail script and the 3-sentence email.","tips":["Voicemail: name, purpose, one date-ask, number twice — nothing that needs writing down beyond the number.","Email: everything referenceable — dates offered, what the meeting covers, how to reply.","Each should mention the other: 'I also emailed / I also left a voicemail.'"],"focus":["audience","concision"],"placeholder":"Hi Ms. Okafor, it's Mr. Reyes, Sam's teacher. I'd like to find 20 minutes this week —"},
    {"id":"together-edu-early-18","level":"early","profession":"education","title":"The reply-all recovery","scenario":"You replied-all to a staff thread with a joke about the new dismissal procedure — mildly snarky, and the assistant principal who designed it was on the thread. The recovery message is a composition test: ownership without groveling, brief, and it has to close the incident rather than extend it.","task":"Write the 2-sentence message to the assistant principal.","tips":["Own it specifically and once: the joke was at your procedure's expense and I sent it to everyone.","No essay — length reads as anxiety, and anxiety invites a longer incident.","End forward-looking: one real piece of engagement with the procedure itself."],"focus":["concision","audience"],"placeholder":"That joke was at your work's expense and I shouldn't have sent it — I'm sorry."},
    {"id":"together-edu-early-19","level":"early","profession":"education","title":"The data slide, humanized","scenario":"At curriculum night you're presenting class assessment data to 30 families. The stack in play: translate the jargon (audience), lead with the takeaway (BLUF), one number that matters (precision), and pre-answer the question every parent brought: what does this mean for MY kid?","task":"Write the 4-sentence spoken walkthrough of the slide.","tips":["Open with the sentence the data adds up to — not the chart's axes.","Translate every benchmark into 'what your child can do' language.","Close by routing the individual question: how each family gets their own child's picture."],"focus":["audience","impact"],"placeholder":"Here's what this chart says in one sentence: this class reads more, and better, than it did in September."},
    {"id":"together-edu-early-20","level":"early","profession":"education","title":"The summer-program application email","scenario":"You're applying to teach at a selective summer institute. The application email is everything at once: a subject line that gets opened, a first line that states the ask, evidence over adjectives ('raised reading scores' with the number), and short enough to respect a director's inbox.","task":"Write the email: subject line plus 4 sentences.","tips":["Subject line does real work: role, your strongest credential, five words.","Sentence one is the application, not the throat-clearing.","One quantified result and one named skill beat a paragraph of enthusiasm."],"focus":["concision","impact"],"placeholder":"Subject: Applying — 4th grade teacher, reading-growth data attached"},
    {"id":"together-edu-early-21","level":"early","profession":"education","title":"Closing the twelve-email thread","scenario":"A homework dispute with a parent has run twelve emails over two weeks. You've met, agreed on a plan, and now you're writing the final message — the one that documents the agreement, thanks without gushing, and closes the loop so firmly that email thirteen never comes.","task":"Write the 3-4 sentence closing email.","tips":["Restate the agreed plan in numbered points — this email IS the record.","Name the next scheduled check-in; open loops reopen threads.","Warm, brief, final: the tone of a door closing gently."],"focus":["structure","clarity"],"placeholder":"Thank you for Tuesday's conversation — here's the plan we agreed on, so we have it in one place."},
    {"id":"together-edu-early-22","level":"early","profession":"education","title":"The nomination that gets read","scenario":"You're nominating your mentor teacher for the district award. The form gives 200 words against dozens of competing nominations that all say 'dedicated' and 'goes above and beyond.' Yours needs the full stack: a lead that stops the reader, one scene, one number, zero clichés.","task":"Write the 200-word-or-fewer nomination's first 3 sentences.","tips":["Open with the scene, not the adjectives: what you watched her do.","One number that proves scale: 22 years, 14 student teachers trained.","If a sentence could appear in anyone's nomination, cut it."],"focus":["impact","precision"],"placeholder":"At 7:05 every morning, there's a line of teenagers outside Room 209 — and half of them aren't even her students."},
    {"id":"together-edu-early-23","level":"early","profession":"education","title":"The year-one reflection","scenario":"Your principal asks every first-year teacher for a one-page reflection: what worked, what didn't, what you need for next year. It's also, quietly, a writing sample your rehire file keeps. Honest about failures, evidenced about wins, specific in the ask — structured so she reads all of it.","task":"Write the reflection's 3 headline sentences: the win with evidence, the honest miss, the specific need.","tips":["The win carries a number; the miss carries what you changed because of it.","An honest miss, well-analyzed, reads as strength in a reflection.","The 'need' is one concrete resource with a reason, not a wish list."],"focus":["structure","precision"],"placeholder":"What worked: small-group math — my lowest quartile grew 1.4 levels, double last year's rate."},
    {"id":"together-edu-early-24","level":"early","profession":"education","title":"Five minutes to teach the teachers","scenario":"You've been asked to share your exit-ticket routine at Friday's PD — five minutes, to colleagues who've watched a hundred share-outs die in vagueness. The full toolkit: why-it-matters in one line, the routine in three steps, one result, and the handout that lets them start Monday.","task":"Write the 5-sentence spoken share-out.","tips":["Open with the problem it solves — the one every teacher in the room has.","Three steps, numbered aloud; more than three and it becomes a webinar.","End with the artifact: the template is in your mailboxes, Monday-ready."],"focus":["structure","concision"],"placeholder":"This routine answers one question: did they actually learn what I just taught — today, not at the unit test."},
    {"id":"together-edu-early-25","level":"early","profession":"education","title":"The capstone rewrite","scenario":"Find the worst email you actually sent this year — for most first-year teachers it's a long, buried-lede, jargon-flecked message sent at 11pm. Yours announced the reading-buddy program in 500 words, and three families asked questions it had technically answered. Rewrite it with everything you now know.","task":"Write the replacement: subject line plus a 4-sentence body.","tips":["Diagnose before rewriting: where was the lede? What did skimmers miss?","Apply the stack in order: point first, audience language, evidence, cut a third.","Compare word counts when done — the delta is your year's progress, measurable."],"focus":["concision","structure"],"placeholder":"Subject: Reading buddies start Tuesday — one form needed by Friday"}
  ],
};
